      doc.fontSize(12).font("Helvetica").text("Inspection Report for Property Owner", { align: "center" });
      doc.moveDown(0.5);
      doc.moveTo(50, doc.y).lineTo(545, doc.y).stroke("#cccccc");
      doc.moveDown(1);

      // Greeting
      const ownerName = report.ownerName || "Owner";
      doc.fontSize(12).font("Helvetica").text(`Hi ${ownerName},`);
      doc.moveDown(0.5);
      doc.text("Following the inspection of your unit, we've identified both damages and missing items.");
      doc.moveDown(1);

      // Unit info
      if (unit) {
        doc.fontSize(10).font("Helvetica-Bold").text("Unit: ", { continued: true });
        doc.font("Helvetica").text(`${unit.propertyName} - ${unit.unitNumber}`);
      }
      if (task) {
        doc.fontSize(10).font("Helvetica-Bold").text("Inspection Date: ", { continued: true });
        doc.font("Helvetica").text(new Date(task.createdAt).toLocaleDateString());
      }
      doc.moveDown(1);

      // Group items by category
      const groupedItems: Record<string, typeof items> = {};
      for (const item of items) {
        const cat = categoryMap.get(item.categoryId);
        const catName = cat?.name || "Uncategorized";
        if (!groupedItems[catName]) groupedItems[catName] = [];
        groupedItems[catName].push(item);
      }

      // Damages section (High + Lower priority)
      const damageItems = groupedItems["Damage"] || [];
      if (damageItems.length > 0) {
        doc.fontSize(16).font("Helvetica-Bold").text("Damages");
        doc.moveDown(0.3);
        doc.moveTo(50, doc.y).lineTo(545, doc.y).stroke("#ef4444");
        doc.moveDown(0.5);

        doc.text("I'll start with the damages in order of priority:");
        doc.moveDown(0.5);

        const highPriority = damageItems.filter(i => i.priority === "HIGH");
        const lowerPriority = damageItems.filter(i => i.priority !== "HIGH");

        if (highPriority.length > 0) {
          doc.fontSize(12).font("Helvetica-Bold").text("High priority (must be fixed before we go live):");
          doc.moveDown(0.3);
          for (const item of highPriority) {
            doc.fontSize(10).font("Helvetica");
            const quoteText = item.repairQuote ? ` — Repair quote: ${item.repairQuote}` : "";
            doc.text(`  •  ${item.roomName} — ${item.itemName}: ${item.description || "Needs attention"}${quoteText}`, { indent: 10 });
          }
          doc.moveDown(0.5);
        }

        if (lowerPriority.length > 0) {
          doc.fontSize(12).font("Helvetica-Bold").text("Lower priority (cosmetic, not deal-breakers but recommended):");
          doc.moveDown(0.3);
          for (const item of lowerPriority) {
            doc.fontSize(10).font("Helvetica");
            const quoteText = item.repairQuote ? ` — Repair quote: ${item.repairQuote}` : "";
            doc.text(`  •  ${item.roomName} — ${item.itemName}: ${item.description || "Needs attention"}${quoteText}`, { indent: 10 });
          }
          doc.moveDown(0.5);
        }
        doc.moveDown(0.5);
      }

      // Missing Items section
      const missingItems = groupedItems["Missing"] || [];
      if (missingItems.length > 0) {
        doc.fontSize(16).font("Helvetica-Bold").text("Missing Items");
        doc.moveDown(0.3);
        doc.moveTo(50, doc.y).lineTo(545, doc.y).stroke("#8b5cf6");
        doc.moveDown(0.5);

        doc.fontSize(11).font("Helvetica").text("Here's the list of items identified as missing:");
        doc.moveDown(0.3);
        for (const item of missingItems) {
          doc.fontSize(10).font("Helvetica").text(`  •  ${item.roomName} — ${item.itemName}${item.description ? `: ${item.description}` : ""}`, { indent: 10 });
        }
        doc.moveDown(0.5);

        if (report.amazonCartLink) {
          doc.fontSize(10).font("Helvetica").text("Here is the Amazon cart link with the missing items compiled for your approval:");
          doc.fontSize(10).fillColor("#3b82f6").text(report.amazonCartLink, { link: report.amazonCartLink, underline: true });
          doc.fillColor("#000000");
        }
        doc.moveDown(0.5);
      }

      // Other categories
      for (const [catName, catItems] of Object.entries(groupedItems)) {
        if (catName === "Damage" || catName === "Missing" || catName === "Good") continue;
        if (catItems.length === 0) continue;

        const cat = categories.find(c => c.name === catName);
        doc.fontSize(16).font("Helvetica-Bold").text(catName);
        doc.moveDown(0.3);
        doc.moveTo(50, doc.y).lineTo(545, doc.y).stroke(cat?.color || "#6b7280");
        doc.moveDown(0.5);

        for (const item of catItems) {
          doc.fontSize(10).font("Helvetica").text(`  •  ${item.roomName} — ${item.itemName}${item.description ? `: ${item.description}` : ""}`, { indent: 10 });
        }
        doc.moveDown(0.5);
      }

      // Closing message
      doc.moveDown(1);
      if (report.closingMessage) {
        doc.fontSize(11).font("Helvetica").text(report.closingMessage);
      }

      // Footer
      doc.moveDown(2);
      doc.fontSize(8).fillColor("#999999").text("Generated by Toronto Boutique Apartments Inspection System", { align: "center" });
      doc.text(`Report generated on ${new Date().toLocaleDateString()}`, { align: "center" });

      doc.end();
    } catch (error) {
      console.error("Error generating owner report PDF:", error);
      res.status(500).json({ message: "Failed to generate PDF" });
    }
  });

  // =========== SEED DATA ROUTE ===========
  app.post("/api/seed", async (req, res) => {
    try {
      // Only allow seeding in development
      if (process.env.NODE_ENV === "production") {
        return res.status(403).json({ message: "Seeding is disabled in production" });
      }

      // Check if data already exists
      const existingUsers = await storage.getUsers();
      if (existingUsers.length > 4) {
        return res.json({ message: "Seed data already exists", seeded: false });
      }

      const passwordHash = hashPassword("demo123");

      // Create demo users: 2 inspectors, 2 PMs, 1 admin
      const demoUsers = [
        { name: "Demo Inspector 1", email: "inspector1@tba.com", role: "INSPECTOR" as const, passwordHash },
        { name: "Demo Inspector 2", email: "inspector2@tba.com", role: "INSPECTOR" as const, passwordHash },
        { name: "Demo PM 1", email: "pm1@tba.com", role: "PM" as const, passwordHash },
        { name: "Demo PM 2", email: "pm2@tba.com", role: "PM" as const, passwordHash },
        { name: "Demo Admin", email: "demoadmin@tba.com", role: "ADMIN" as const, passwordHash },
      ];

      const createdUsers: Array<{ id: string; role: string }> = [];
      for (const user of demoUsers) {
        const existing = await storage.getUserByEmail(user.email);
        if (!existing) {
          const created = await storage.createUser(user);
          createdUsers.push({ id: created.id, role: created.role });
        } else {
          createdUsers.push({ id: existing.id, role: existing.role });
        }
      }

      // Create 5 demo units
      const demoUnits = [
        { propertyName: "Sunset Apartments", unitNumber: "101", address: "123 Sunset Blvd, Los Angeles, CA 90001" },
        { propertyName: "Sunset Apartments", unitNumber: "202", address: "123 Sunset Blvd, Los Angeles, CA 90001" },
        { propertyName: "Ocean View Condos", unitNumber: "A1", address: "456 Pacific Coast Hwy, Malibu, CA 90265" },
        { propertyName: "Downtown Lofts", unitNumber: "PH1", address: "789 Main St, Los Angeles, CA 90012" },
        { propertyName: "Garden Villas", unitNumber: "5B", address: "321 Garden Way, Pasadena, CA 91101" },
      ];

      const createdUnits: string[] = [];
      const existingUnits = await storage.getUnits();
      for (const unit of demoUnits) {
        const existing = existingUnits.find(u => u.unitNumber === unit.unitNumber && u.propertyName === unit.propertyName);
        if (!existing) {
          const created = await storage.createUnit(unit);
          createdUnits.push(created.id);
        } else {
          createdUnits.push(existing.id);
        }
      }

      // Get user IDs by role
      const inspectors = createdUsers.filter(u => u.role === "INSPECTOR");
      const pms = createdUsers.filter(u => u.role === "PM" || u.role === "ADMIN");

      // Create inspection template if not exists
      const existingTemplate = await storage.getTemplateByType("FULL_INSPECTION");
      let templateId = existingTemplate?.id;

      if (!templateId) {
        const seedRooms: TemplateRoom[] = [
          {
            key: "kitchen",
            name: "Kitchen",
            items: [
              { key: "appliances", label: "Appliances functional", required: true, inputType: "PASS_FAIL", requiresMedia: false },
              { key: "cabinets", label: "Cabinets condition", required: true, inputType: "CONDITION", requiresMedia: false },
              { key: "sink", label: "Sink and faucet", required: true, inputType: "PASS_FAIL", requiresMedia: false },
            ],
          },
          {
            key: "bathroom",
            name: "Bathroom",
            items: [
              { key: "toilet", label: "Toilet functional", required: true, inputType: "PASS_FAIL", requiresMedia: false },
              { key: "shower", label: "Shower/tub condition", required: true, inputType: "CONDITION", requiresMedia: false },
              { key: "vanity", label: "Vanity and sink", required: true, inputType: "PASS_FAIL", requiresMedia: false },
            ],
          },
          {
            key: "bedroom",
            name: "Bedroom",
            items: [
              { key: "flooring", label: "Flooring condition", required: true, inputType: "CONDITION", requiresMedia: false },
              { key: "closet", label: "Closet doors/shelves", required: true, inputType: "PASS_FAIL", requiresMedia: false },
              { key: "windows", label: "Windows and blinds", required: true, inputType: "PASS_FAIL", requiresMedia: false },
            ],
          },
        ];
        const template = await storage.createTemplate({
          name: "Standard Full Inspection",
          type: "FULL_INSPECTION",
          rooms: seedRooms,
        });
        templateId = template.id;
      }

      // Create 3 inspection tasks with different statuses
      if (createdUnits.length >= 3 && inspectors.length >= 1 && pms.length >= 1) {
        const taskStatuses = ["ASSIGNED", "IN_PROGRESS", "SUBMITTED"] as const;
        const existingTasks = await storage.getInspectionTasks();

        if (existingTasks.length < 3) {
          for (let i = 0; i < 3; i++) {
            await storage.createInspectionTask({
              type: "FULL_INSPECTION",
              unitId: createdUnits[i],
              assignedToUserId: inspectors[i % inspectors.length].id,
              responsiblePmId: pms[i % pms.length].id,
              templateId: templateId,
              status: taskStatuses[i],
              createdById: pms[0].id,
            });
          }
        }
      }

      // Create a few quick reports
      if (pms.length >= 1 && inspectors.length >= 1) {
        const existingReports = await storage.getQuickReports();
        if (existingReports.length < 3) {
          const quickReportData = [
            { unitNumber: "101", location: "KITCHEN" as const, severity: "MINOR" as const, description: "Minor scratch on countertop near sink area" },
            { unitNumber: "202", location: "BATHROOM" as const, severity: "MODERATE" as const, description: "Leaking faucet needs replacement" },
            { unitNumber: "A1", location: "BEDROOM" as const, severity: "SEVERE" as const, description: "Large water stain on ceiling indicates possible roof leak" },
          ];

          for (const data of quickReportData) {
            await storage.createQuickReport({
              ...data,
              createdById: inspectors[0].id,
              responsiblePmId: pms[0].id,
              status: "NEW",
            });
          }
        }
      }

      res.json({ 
        message: "Seed data created successfully", 
        seeded: true,
        stats: {
          users: createdUsers.length,
          units: createdUnits.length,
        }
      });
    } catch (error) {
      console.error("Seed error:", error);
      res.status(500).json({ message: "Failed to seed data" });
    }
  });

  return httpServer;
}

