import { Avatar, AvatarFallback } from "@/components/ui/avatar";
import { StatusPill } from "./status-pill";
import { ActionsDropdown } from "./actions-dropdown";
import type { InspectionTask, User, Unit } from "@shared/schema";

interface InspectionInboxTableProps {
  tasks: InspectionTask[];
  users: User[];
  units: Unit[];
  isLoading?: boolean;
}

export function InspectionInboxTable({ tasks, users, units, isLoading }: InspectionInboxTableProps) {
  const getUserName = (userId: string) => {
    const user = users.find((u) => u.id === userId);
    return user?.name || "Unknown";
  };

  const getUnitDisplay = (unitId: string) => {
    const unit = units.find((u) => u.id === unitId);
    return unit ? `${unit.propertyName} - ${unit.unitNumber}` : `Unit ${unitId}`;
  };

  const getUnitInitial = (unitId: string) => {
    const unit = units.find((u) => u.id === unitId);
    return unit?.propertyName?.charAt(0).toUpperCase() || "U";
  };

  const formatDate = (date: Date | string) => {
    return new Date(date).toLocaleDateString("en-US", {
      month: "short",
      day: "numeric",
      year: "numeric",
    });
  };

  const formatType = (type: string) => {
    return type === "FULL_INSPECTION" ? "Full Inspection" : "Onboarding";
  };

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
      <div className="px-4 md:px-6 py-4 border-b border-gray-100">
        <h2 className="text-lg font-semibold text-gray-900">Inspection Inbox</h2>
      </div>

      {isLoading ? (
        <div className="px-6 py-12 text-center text-gray-500">
          <div className="flex items-center justify-center gap-2">
            <div className="h-4 w-4 border-2 border-violet-600 border-t-transparent rounded-full animate-spin" />
            Loading inspections...
          </div>
        </div>
      ) : !tasks || tasks.length === 0 ? (
        <div className="px-6 py-12 text-center text-gray-500">
          No inspections found
        </div>
      ) : (
        <>
          <div className="hidden md:block overflow-x-auto">
            <table className="w-full" data-testid="table-inspection-inbox">
              <thead>
                <tr className="border-b border-gray-100 bg-gray-50/50">
                  <th className="px-6 py-3 text-left text-xs font-semibold text-gray-500 uppercase tracking-wider">
                    Unit
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-semibold text-gray-500 uppercase tracking-wider">
                    Inspector
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-semibold text-gray-500 uppercase tracking-wider">
                    Type
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-semibold text-gray-500 uppercase tracking-wider">
                    Status
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-semibold text-gray-500 uppercase tracking-wider">
                    Date Submitted
                  </th>
                  <th className="px-6 py-3 text-right text-xs font-semibold text-gray-500 uppercase tracking-wider">
                    Actions
                  </th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-100">
                {tasks.map((task) => (
                  <tr 
                    key={task.id} 
                    className="hover:bg-gray-50/50 transition-colors"
                    data-testid={`row-task-${task.id}`}
                  >
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-3">
                        <Avatar className="h-8 w-8">
                          <AvatarFallback className="bg-violet-100 text-violet-700 text-xs font-semibold">
                            {getUnitInitial(task.unitId)}
                          </AvatarFallback>
                        </Avatar>
                        <span className="font-medium text-gray-900 text-sm">
                          {getUnitDisplay(task.unitId)}
                        </span>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className="text-gray-700 text-sm">
                        {getUserName(task.assignedToUserId)}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      <span className="text-gray-700 text-sm">
                        {formatType(task.type)}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      <StatusPill status={task.status} />
                    </td>
                    <td className="px-6 py-4">
                      <span className="text-gray-500 text-sm">
                        {formatDate(task.createdAt)}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <ActionsDropdown taskId={task.id} />
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <div className="md:hidden divide-y divide-gray-100" data-testid="mobile-inspection-inbox">
            {tasks.map((task) => (
              <div
                key={task.id}
                className="p-4 space-y-2"
                data-testid={`card-task-${task.id}`}
              >
                <div className="flex items-center justify-between gap-2">
                  <div className="flex items-center gap-2 min-w-0">
                    <Avatar className="h-8 w-8 flex-shrink-0">
                      <AvatarFallback className="bg-violet-100 text-violet-700 text-xs font-semibold">
                        {getUnitInitial(task.unitId)}
                      </AvatarFallback>
                    </Avatar>
                    <span className="font-medium text-gray-900 text-sm truncate">
                      {getUnitDisplay(task.unitId)}
                    </span>
                  </div>
                  <ActionsDropdown taskId={task.id} />
                </div>
                <div className="flex items-center flex-wrap gap-2 text-sm">
                  <StatusPill status={task.status} />
                  <span className="text-gray-500">{formatType(task.type)}</span>
                </div>
                <div className="flex items-center justify-between gap-2 text-xs text-gray-500">
                  <span>{getUserName(task.assignedToUserId)}</span>
                  <span>{formatDate(task.createdAt)}</span>
                </div>
              </div>
            ))}
          </div>
        </>
      )}
    </div>
  );
}

