import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { useAuth } from "@/lib/auth";
import { useRoute, useLocation } from "wouter";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger,
} from "@/components/ui/accordion";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "@/components/ui/dialog";
import { queryClient, apiRequest } from "@/lib/queryClient";
import { StatusPill } from "@/components/portal";
import {
  ArrowLeft,
  CheckCircle2,
  AlertTriangle,
  XCircle,
  FileWarning,
  Download,
  MoreVertical,
  CheckSquare,
  Send,
  MessageSquarePlus,
  Play,
  Image,
  Camera,
  Video,
} from "lucide-react";
import type {
  InspectionTask,
  Unit,
  ChecklistResponse,
  Media,
  InspectionTemplate,
  TemplateRoom,
  PmNote,
} from "@shared/schema";

interface InspectorInfo {
  id: string;
  name: string;
  email: string;
  role: string;
}

interface InspectionDetails {
  task: InspectionTask;
  unit: Unit | null;
  responses: ChecklistResponse[];
  media: Media[];
  inspector: InspectorInfo | null;
  pm: InspectorInfo | null;
  template: InspectionTemplate | null;
}

export default function InspectionReportPage() {
  const { user } = useAuth();
  const [, setLocation] = useLocation();
  const [, params] = useRoute("/pm/inspection/:inspectionId");
  const inspectionId = params?.inspectionId;
  const [addNoteOpen, setAddNoteOpen] = useState(false);
  const [newNote, setNewNote] = useState("");

  // Fetch inspection details
  const { data: details, isLoading } = useQuery<InspectionDetails>({
    queryKey: ["/api/inspection-tasks", inspectionId, "details"],
    enabled: !!inspectionId,
  });

  // Fetch PM notes for the unit
  const { data: pmNotes } = useQuery<PmNote[]>({
    queryKey: ["/api/units", details?.unit?.id, "pm-notes"],
    enabled: !!details?.unit?.id,
  });

  // Update task status mutation
  const updateStatusMutation = useMutation({
    mutationFn: async (status: string) => {
      return apiRequest("PATCH", `/api/inspection-tasks/${inspectionId}`, { status });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/inspection-tasks", inspectionId, "details"] });
      queryClient.invalidateQueries({ queryKey: ["/api/inspection-tasks"] });
    },
  });

  // Add PM note mutation
  const addNoteMutation = useMutation({
    mutationFn: async (content: string) => {
      return apiRequest("POST", `/api/units/${details?.unit?.id}/pm-notes`, { content });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/units", details?.unit?.id, "pm-notes"] });
      setNewNote("");
      setAddNoteOpen(false);
    },
  });

  if (!user || (user.role !== "PM" && user.role !== "ADMIN")) {
    return (
      <div className="p-6 text-center">
        <p className="text-muted-foreground">Access denied. PM or Admin role required.</p>
      </div>
    );
  }

  if (isLoading) {
    return (
      <div className="p-6">
        <div className="animate-pulse space-y-4">
          <div className="h-8 w-48 bg-muted rounded" />
          <div className="h-32 bg-muted rounded" />
          <div className="h-64 bg-muted rounded" />
        </div>
      </div>
    );
  }

  if (!details?.task) {
    return (
      <div className="p-6 text-center">
        <p className="text-muted-foreground">Inspection not found.</p>
        <Button variant="ghost" onClick={() => setLocation("/pm")} className="mt-4">
          <ArrowLeft className="w-4 h-4 mr-2" />
          Back to Dashboard
        </Button>
      </div>
    );
  }

  const { task, unit, responses, media, inspector, template } = details;

  // Calculate summary stats
  const goodCount = responses.filter((r) => r.result === "GOOD" || r.result === "PASS").length;
  const replacementCount = responses.filter((r) => r.result === "NEED_REPLACEMENT").length;
  const missingCount = responses.filter((r) => r.result === "MISSING").length;
  const issuesCount = responses.filter((r) => r.result === "FAIL" || r.notes).length;

  // Check completion status
  // All responses have been recorded (at least one response exists)
  const hasResponses = responses.length > 0;
  // Check if all responses have a valid result (not just empty)
  const allItemsAnswered = responses.every((r) => r.result && r.result !== "NA");
  const checklistComplete = hasResponses && allItemsAnswered;

  // Media is complete if all responses that require media have it satisfied
  // requiredMediaSatisfied = true means required media has been uploaded
  const mediaComplete = responses.every((r) => r.requiredMediaSatisfied === true);

  // Group responses by room
  const roomGroups: Record<string, ChecklistResponse[]> = {};
  responses.forEach((r) => {
    if (!roomGroups[r.roomKey]) {
      roomGroups[r.roomKey] = [];
    }
    roomGroups[r.roomKey].push(r);
  });

  // Get media for a specific response
  const getMediaForResponse = (responseId: string) => {
    return media.filter((m) => m.checklistResponseId === responseId);
  };

  // Get room name from template or key
  const getRoomName = (roomKey: string) => {
    if (template?.rooms) {
      const room = (template.rooms as TemplateRoom[]).find((r) => r.key === roomKey);
      if (room) return room.name;
    }
    return roomKey.replace(/_/g, " ").replace(/\b\w/g, (l) => l.toUpperCase());
  };

  // Get item label from template or key
  const getItemLabel = (roomKey: string, itemKey: string) => {
    if (template?.rooms) {
      const room = (template.rooms as TemplateRoom[]).find((r) => r.key === roomKey);
      if (room) {
        const item = room.items.find((i) => i.key === itemKey);
        if (item) return item.label;
      }
    }
    return itemKey.replace(/_/g, " ").replace(/\b\w/g, (l) => l.toUpperCase());
  };

  // Get status color for result
  const getResultColor = (result: string) => {
    switch (result) {
      case "GOOD":
      case "PASS":
      case "YES":
        return "bg-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-400";
      case "NEED_REPLACEMENT":
        return "bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-400";
      case "MISSING":
        return "bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400";
      case "FAIL":
      case "NO":
        return "bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400";
      case "NA":
        return "bg-gray-100 text-gray-600 dark:bg-gray-800 dark:text-gray-400";
      default:
        return "bg-gray-100 text-gray-600 dark:bg-gray-800 dark:text-gray-400";
    }
  };

  // Issues - items with FAIL, MISSING, NEED_REPLACEMENT or notes
  const issueItems = responses.filter(
    (r) => r.result === "FAIL" || r.result === "MISSING" || r.result === "NEED_REPLACEMENT" || r.notes
  );

  // Data collection groups (Part 2)
  const dataCollectionGroups = [
    { key: "bedroom", label: "Bedroom" },
    { key: "bathroom", label: "Bathroom" },
    { key: "living_room", label: "Living Room" },
    { key: "kitchen", label: "Kitchen" },
    { key: "dining", label: "Dining" },
    { key: "hallway", label: "Hallway/Storage" },
    { key: "general", label: "General" },
    { key: "thermostat", label: "Thermostat" },
    { key: "wifi", label: "WiFi" },
  ];

  const canDownloadPdf = task.status === "SUBMITTED" || task.status === "REVIEWED" || task.status === "ARCHIVED";
  const canMarkReviewed = task.status === "SUBMITTED";
  const canMarkSent = task.status === "REVIEWED";

  return (
    <div className="min-h-screen bg-background">
      {/* Header */}
      <div className="border-b bg-card">
        <div className="max-w-7xl mx-auto px-4 py-4">
          <div className="flex items-center justify-between gap-4 flex-wrap">
            <div className="flex items-center gap-3">
              <Button
                variant="ghost"
                size="icon"
                onClick={() => setLocation("/pm")}
                data-testid="button-back"
              >
                <ArrowLeft className="w-5 h-5" />
              </Button>
              <div>
                <h1 className="text-xl font-semibold" data-testid="text-inspection-title">
                  {task.type === "FULL_INSPECTION" ? "Full Inspection" : "Onboarding Inspection"}
                </h1>
                <p className="text-sm text-muted-foreground">
                  {unit ? `${unit.propertyName} - ${unit.unitNumber}` : "Unknown Unit"}
                </p>
              </div>
            </div>

            {/* PM Controls */}
            <div className="flex items-center gap-2">
              {canDownloadPdf && (
                <>
                  <Button
                    variant="default"
                    size="sm"
                    onClick={() => setLocation(`/pm/owner-report/${inspectionId}`)}
                    data-testid="button-owner-report"
                  >
                    <FileWarning className="w-4 h-4 mr-2" />
                    Owner Report
                  </Button>
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => window.open(`/api/pm/inspections/${inspectionId}/pdf`, "_blank")}
                    data-testid="button-download-pdf"
                  >
                    <Download className="w-4 h-4 mr-2" />
                    Download PDF
                  </Button>
                </>
              )}

              <DropdownMenu>
                <DropdownMenuTrigger asChild>
                  <Button variant="outline" size="icon" data-testid="button-actions">
                    <MoreVertical className="w-4 h-4" />
                  </Button>
                </DropdownMenuTrigger>
                <DropdownMenuContent align="end">
                  {canMarkReviewed && (
                    <DropdownMenuItem
                      onClick={() => updateStatusMutation.mutate("REVIEWED")}
                      data-testid="action-mark-reviewed"
                    >
                      <CheckSquare className="w-4 h-4 mr-2" />
                      Mark Reviewed
                    </DropdownMenuItem>
                  )}
                  {canMarkSent && (
                    <DropdownMenuItem
                      onClick={() => updateStatusMutation.mutate("ARCHIVED")}
                      data-testid="action-mark-sent"
                    >
                      <Send className="w-4 h-4 mr-2" />
                      Mark Sent
                    </DropdownMenuItem>
                  )}
                  <DropdownMenuItem
                    onClick={() => setAddNoteOpen(true)}
                    data-testid="action-add-note"
                  >
                    <MessageSquarePlus className="w-4 h-4 mr-2" />
                    Add PM Note
                  </DropdownMenuItem>
                </DropdownMenuContent>
              </DropdownMenu>
            </div>
          </div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-4 py-6 space-y-6">
        {/* 1. Executive Summary */}
        <section data-testid="section-executive-summary">
          <h2 className="text-lg font-semibold mb-4">Executive Summary</h2>

          {/* Unit Details Row */}
          <Card className="p-4 mb-4">
            <div className="flex flex-wrap gap-6 text-sm">
              <div>
                <span className="text-muted-foreground">Unit:</span>{" "}
                <span className="font-medium">{unit ? `${unit.propertyName} - ${unit.unitNumber}` : "N/A"}</span>
              </div>
              <div>
                <span className="text-muted-foreground">Date:</span>{" "}
                <span className="font-medium">{new Date(task.createdAt).toLocaleDateString()}</span>
              </div>
              <div>
                <span className="text-muted-foreground">Inspector:</span>{" "}
                <span className="font-medium">{inspector?.name || "N/A"}</span>
              </div>
              <div className="flex items-center gap-1">
                <span className="text-muted-foreground">Status:</span>{" "}
                <StatusPill status={task.status} />
              </div>
            </div>
          </Card>

          {/* Summary Cards */}
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-4">
            <Card className="p-4 text-center">
              <div className="flex justify-center mb-2">
                <CheckCircle2 className="w-8 h-8 text-emerald-500" />
              </div>
              <div className="text-2xl font-bold text-emerald-600" data-testid="count-good">
                {goodCount}
              </div>
              <div className="text-sm text-muted-foreground">Good</div>
            </Card>
            <Card className="p-4 text-center">
              <div className="flex justify-center mb-2">
                <AlertTriangle className="w-8 h-8 text-amber-500" />
              </div>
              <div className="text-2xl font-bold text-amber-600" data-testid="count-replacement">
                {replacementCount}
              </div>
              <div className="text-sm text-muted-foreground">Replacement</div>
            </Card>
            <Card className="p-4 text-center">
              <div className="flex justify-center mb-2">
                <XCircle className="w-8 h-8 text-red-500" />
              </div>
              <div className="text-2xl font-bold text-red-600" data-testid="count-missing">
                {missingCount}
              </div>
              <div className="text-sm text-muted-foreground">Missing</div>
            </Card>
            <Card className="p-4 text-center">
              <div className="flex justify-center mb-2">
                <FileWarning className="w-8 h-8 text-orange-500" />
              </div>
              <div className="text-2xl font-bold text-orange-600" data-testid="count-issues">
                {issuesCount}
              </div>
              <div className="text-sm text-muted-foreground">Issues</div>
            </Card>
          </div>

          {/* Completion Badges */}
          <div className="flex gap-3 flex-wrap">
            {checklistComplete && (
              <Badge variant="secondary" className="gap-1" data-testid="badge-checklist-complete">
                <CheckCircle2 className="w-3 h-3" />
                Checklist complete
              </Badge>
            )}
            {mediaComplete && (
              <Badge variant="secondary" className="gap-1" data-testid="badge-media-complete">
                <Camera className="w-3 h-3" />
                Media complete
              </Badge>
            )}
          </div>
        </section>

        {/* 2. Room-by-Room Condition Overview */}
        <section data-testid="section-room-conditions">
          <h2 className="text-lg font-semibold mb-4">Room-by-Room Condition Overview</h2>
          <Card>
            <Accordion type="multiple" className="w-full">
              {Object.entries(roomGroups).map(([roomKey, items]) => (
                <AccordionItem key={roomKey} value={roomKey}>
                  <AccordionTrigger className="px-4 hover:no-underline" data-testid={`accordion-room-${roomKey}`}>
                    <div className="flex items-center gap-3">
                      <span className="font-medium">{getRoomName(roomKey)}</span>
                      <Badge variant="outline" className="text-xs">
                        {items.length} items
                      </Badge>
                    </div>
                  </AccordionTrigger>
                  <AccordionContent className="px-4 pb-4">
                    <div className="space-y-3">
                      {items.map((item) => {
                        const itemMedia = getMediaForResponse(item.id);
                        const isProblem =
                          item.result === "FAIL" ||
                          item.result === "MISSING" ||
                          item.result === "NEED_REPLACEMENT";

                        return (
                          <div
                            key={item.id}
                            className={`p-3 rounded-lg border ${
                              isProblem ? "bg-red-50 dark:bg-red-900/10 border-red-200 dark:border-red-800" : "bg-muted/50"
                            }`}
                            data-testid={`item-${item.id}`}
                          >
                            <div className="flex items-center justify-between gap-2 flex-wrap">
                              <span className="font-medium">{getItemLabel(roomKey, item.itemKey)}</span>
                              <Badge className={`${getResultColor(item.result)} border-0`}>
                                {item.result.replace(/_/g, " ")}
                              </Badge>
                            </div>
                            {item.notes && (
                              <p className="text-sm text-muted-foreground mt-2 italic">
                                Note: {item.notes}
                              </p>
                            )}
                            {isProblem && itemMedia.length > 0 && (
                              <div className="mt-3 flex gap-2 flex-wrap">
                                {itemMedia.map((m) => (
                                  <div
                                    key={m.id}
                                    className="relative w-16 h-16 rounded overflow-hidden border"
                                  >
                                    {m.type === "PHOTO" ? (
                                      <img
                                        src={m.url}
                                        alt="Evidence"
                                        className="w-full h-full object-cover"
                                      />
                                    ) : (
                                      <div className="w-full h-full bg-muted flex items-center justify-center">
                                        <Play className="w-6 h-6 text-muted-foreground" />
                                      </div>
                                    )}
                                  </div>
                                ))}
                              </div>
                            )}
                          </div>
                        );
                      })}
                    </div>
                  </AccordionContent>
                </AccordionItem>
              ))}
            </Accordion>
          </Card>
        </section>

        {/* 3. Issues & Damages */}
        {issueItems.length > 0 && (
          <section data-testid="section-issues">
            <h2 className="text-lg font-semibold mb-4">Issues & Damages</h2>
            <Card className="divide-y">
              {issueItems.map((issue) => {
                const issueMedia = getMediaForResponse(issue.id);
                return (
                  <div key={issue.id} className="p-4" data-testid={`issue-${issue.id}`}>
                    <div className="flex items-start justify-between gap-3 flex-wrap">
                      <div className="flex-1">
                        <div className="flex items-center gap-2 flex-wrap mb-1">
                          <span className="font-medium">{getItemLabel(issue.roomKey, issue.itemKey)}</span>
                          <Badge className={`${getResultColor(issue.result)} border-0 text-xs`}>
                            {issue.result.replace(/_/g, " ")}
                          </Badge>
                          {issue.severity && (
                            <Badge
                              variant="outline"
                              className={
                                issue.severity === "HIGH"
                                  ? "border-red-500 text-red-600"
                                  : issue.severity === "MED"
                                  ? "border-amber-500 text-amber-600"
                                  : "border-gray-400 text-gray-600"
                              }
                            >
                              {issue.severity}
                            </Badge>
                          )}
                        </div>
                        <p className="text-sm text-muted-foreground">
                          Location: {getRoomName(issue.roomKey)}
                        </p>
                        {issue.notes && (
                          <p className="text-sm mt-2">{issue.notes}</p>
                        )}
                      </div>
                    </div>

                    {/* Inline Photos/Videos */}
                    {issueMedia.length > 0 && (
                      <div className="mt-3 flex gap-2 flex-wrap">
                        {issueMedia.map((m) => (
                          <a
                            key={m.id}
                            href={m.url}
                            target="_blank"
                            rel="noopener noreferrer"
                            className="relative block w-24 h-24 rounded-lg overflow-hidden border hover-elevate"
                          >
                            {m.type === "PHOTO" ? (
                              <img
                                src={m.url}
                                alt="Issue evidence"
                                className="w-full h-full object-cover"
                              />
                            ) : (
                              <div className="w-full h-full bg-muted flex items-center justify-center">
                                <Video className="w-8 h-8 text-muted-foreground" />
                              </div>
                            )}
                            <div className="absolute bottom-1 right-1 bg-black/50 rounded px-1">
                              {m.type === "PHOTO" ? (
                                <Image className="w-3 h-3 text-white" />
                              ) : (
                                <Play className="w-3 h-3 text-white" />
                              )}
                            </div>
                          </a>
                        ))}
                      </div>
                    )}
                  </div>
                );
              })}
            </Card>
          </section>
        )}

        {/* 4. Data Collection (Part 2) */}
        <section data-testid="section-data-collection">
          <h2 className="text-lg font-semibold mb-4">Data Collection</h2>
          <div className="space-y-4">
            {dataCollectionGroups.map((group) => {
              const groupResponses = responses.filter((r) =>
                r.roomKey.toLowerCase().includes(group.key.toLowerCase())
              );
              if (groupResponses.length === 0) return null;

              return (
                <Card key={group.key} className="overflow-hidden">
                  <div className="px-4 py-3 bg-muted/50 border-b">
                    <h3 className="font-medium">{group.label}</h3>
                  </div>
                  <div className="overflow-x-auto">
                    <table className="w-full text-sm">
                      <thead>
                        <tr className="border-b bg-muted/30">
                          <th className="text-left px-4 py-2 font-medium">Item</th>
                          <th className="text-left px-4 py-2 font-medium">Value</th>
                          <th className="text-left px-4 py-2 font-medium">Notes</th>
                        </tr>
                      </thead>
                      <tbody>
                        {groupResponses.map((r) => (
                          <tr key={r.id} className="border-b last:border-0">
                            <td className="px-4 py-2">{getItemLabel(r.roomKey, r.itemKey)}</td>
                            <td className="px-4 py-2">
                              <Badge className={`${getResultColor(r.result)} border-0 text-xs`}>
                                {r.result === "NA" ? "I don't know" : r.result.replace(/_/g, " ")}
                              </Badge>
                            </td>
                            <td className="px-4 py-2 text-muted-foreground">
                              {r.notes || "-"}
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </Card>
              );
            })}
          </div>
        </section>
      </div>

      {/* Add PM Note Dialog */}
      <Dialog open={addNoteOpen} onOpenChange={setAddNoteOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Add PM Note</DialogTitle>
          </DialogHeader>
          <Textarea
            placeholder="Enter your internal note..."
            value={newNote}
            onChange={(e) => setNewNote(e.target.value)}
            rows={4}
            data-testid="input-pm-note"
          />
          <DialogFooter>
            <Button variant="ghost" onClick={() => setAddNoteOpen(false)}>
              Cancel
            </Button>
            <Button
              onClick={() => addNoteMutation.mutate(newNote)}
              disabled={!newNote.trim() || addNoteMutation.isPending}
              data-testid="button-save-note"
            >
              {addNoteMutation.isPending ? "Saving..." : "Save Note"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

