interface StatusPillProps {
  status: string;
}

const statusConfig: Record<string, { bg: string; text: string; label: string }> = {
  ASSIGNED: { 
    bg: "bg-muted", 
    text: "text-muted-foreground", 
    label: "Draft" 
  },
  IN_PROGRESS: { 
    bg: "bg-muted", 
    text: "text-muted-foreground", 
    label: "Draft" 
  },
  SUBMITTED: { 
    bg: "bg-chart-5/15", 
    text: "text-chart-5", 
    label: "Submitted" 
  },
  REVIEWED: { 
    bg: "bg-chart-2/15", 
    text: "text-chart-2", 
    label: "Reviewed" 
  },
  ARCHIVED: { 
    bg: "bg-chart-3/15", 
    text: "text-chart-3", 
    label: "Sent to Owner" 
  },
};

export function StatusPill({ status }: StatusPillProps) {
  const normalizedStatus = status.toUpperCase().replace(/-/g, "_");
  const config = statusConfig[normalizedStatus] || { 
    bg: "bg-muted", 
    text: "text-muted-foreground", 
    label: status 
  };

  return (
    <span
      className={`inline-flex items-center px-3 py-1.5 rounded-full text-xs font-semibold ${config.bg} ${config.text}`}
      data-testid={`status-pill-${status.toLowerCase()}`}
    >
      {config.label}
    </span>
  );
}

client/src/pages/pm/dashboard.tsx.content:
import { useState, useMemo } from "react";
import { useAuth } from "@/lib/auth";
import { useQuery, useMutation } from "@tanstack/react-query";
import { queryClient, apiRequest } from "@/lib/queryClient";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Avatar, AvatarFallback } from "@/components/ui/avatar";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { StatusPill, ActionsDropdown } from "@/components/portal";
import { useLocation } from "wouter";
import type { InspectionTask, QuickReport, User, Unit } from "@shared/schema";

type InboxItem = {
  id: string;
  sourceType: "inspection" | "quick_report";
  unitId: string;
  unitNumber: string;
  inspectorId: string;
  type: string;
  status: string;
  dateSubmitted: Date;
};

export default function PMDashboardPage() {
  const { user } = useAuth();
  const [, setLocation] = useLocation();

  // Filters state
  const [statusFilter, setStatusFilter] = useState<string>("all");
  const [unitFilter, setUnitFilter] = useState<string>("all");
  const [dateFrom, setDateFrom] = useState<string>("");
  const [dateTo, setDateTo] = useState<string>("");

  // Fetch data
  const { data: tasks, isLoading: tasksLoading } = useQuery<InspectionTask[]>({
    queryKey: ["/api/inspection-tasks"],
  });

  const { data: quickReports, isLoading: reportsLoading } = useQuery<QuickReport[]>({
    queryKey: ["/api/quick-reports"],
  });

  const { data: users } = useQuery<User[]>({
    queryKey: ["/api/users"],
  });

  const { data: units } = useQuery<Unit[]>({
    queryKey: ["/api/units"],
  });

  const isLoading = tasksLoading || reportsLoading;

  // Mutation for updating task status
  const updateTaskMutation = useMutation({
    mutationFn: async ({ taskId, status }: { taskId: string; status: string }) => {
      return apiRequest("PATCH", `/api/inspection-tasks/${taskId}`, { status });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/inspection-tasks"] });
    },
  });

  // Helper functions
  const getUserName = (userId: string) => {
    const foundUser = users?.find((u) => u.id === userId);
    return foundUser?.name || "Unknown";
  };

  const getUnitDisplay = (unitId: string) => {
    const unit = units?.find((u) => u.id === unitId);
    return unit ? `${unit.propertyName} - ${unit.unitNumber}` : `Unit`;
  };

  const getUnitInitial = (unitId: string) => {
    const unit = units?.find((u) => u.id === unitId);
    return unit?.propertyName?.charAt(0).toUpperCase() || "U";
  };

  // Combine inspections and quick reports for this PM only
  const inboxItems = useMemo((): InboxItem[] => {
    if (!user) return [];

    const items: InboxItem[] = [];

    // Add inspection tasks where this PM is responsible
    if (tasks) {
      tasks
        .filter((task) => task.responsiblePmId === user.id)
        .forEach((task) => {
          items.push({
            id: task.id,
            sourceType: "inspection",
            unitId: task.unitId,
            unitNumber: getUnitDisplay(task.unitId),
            inspectorId: task.assignedToUserId,
            type: task.type === "FULL_INSPECTION" ? "Full Inspection" : "Onboarding",
            status: task.status,
            dateSubmitted: new Date(task.createdAt),
          });
        });
    }

    // Add quick reports where this PM is responsible
    if (quickReports) {
      quickReports
        .filter((report) => report.responsiblePmId === user.id)
        .forEach((report) => {
          // Map quick report status to task status for consistency
          const mappedStatus = report.status === "NEW" ? "SUBMITTED" : 
                               report.status === "ACKNOWLEDGED" ? "REVIEWED" : "ARCHIVED";
          items.push({
            id: report.id,
            sourceType: "quick_report",
            unitId: "",
            unitNumber: report.unitNumber,
            inspectorId: report.createdById,
            type: "Quick Report",
            status: mappedStatus,
            dateSubmitted: new Date(report.createdAt),
          });
        });
    }

    // Sort by date descending
    return items.sort((a, b) => b.dateSubmitted.getTime() - a.dateSubmitted.getTime());
  }, [tasks, quickReports, users, units, user]);

  // Apply filters
  const filteredItems = useMemo(() => {
    return inboxItems.filter((item) => {
      // Status filter
      if (statusFilter !== "all" && item.status !== statusFilter) {
        return false;
      }

      // Unit filter
      if (unitFilter !== "all") {
        if (item.unitId && item.unitId !== unitFilter) return false;
        // For quick reports without unitId, check unitNumber text
        if (!item.unitId && item.unitNumber !== unitFilter) return false;
      }

      // Date from filter
      if (dateFrom) {
        const fromDate = new Date(dateFrom);
        if (item.dateSubmitted < fromDate) return false;
      }

      // Date to filter
      if (dateTo) {
        const toDate = new Date(dateTo);
        toDate.setHours(23, 59, 59, 999);
        if (item.dateSubmitted > toDate) return false;
      }

      return true;
    });
  }, [inboxItems, statusFilter, unitFilter, dateFrom, dateTo]);

  const formatDate = (date: Date) => {
    return date.toLocaleDateString("en-US", {
      month: "short",
      day: "numeric",
      year: "numeric",
    });
  };

  const handleView = (item: InboxItem) => {
    if (item.sourceType === "quick_report") {
      setLocation(`/portal/quick-reports`);
    } else {
      setLocation(`/pm/inspection/${item.id}`);
    }
  };

  const handleMarkReviewed = (itemId: string) => {
    updateTaskMutation.mutate({ taskId: itemId, status: "REVIEWED" });
  };

  const handleMarkSent = (itemId: string) => {
    updateTaskMutation.mutate({ taskId: itemId, status: "ARCHIVED" });
  };

  // Get unique units for filter dropdown
  const unitOptions = useMemo(() => {
    if (!units) return [];
    return units.map((unit) => ({
      id: unit.id,
      label: `${unit.propertyName} - ${unit.unitNumber}`,
    }));
  }, [units]);

  return (
    <div className="space-y-8">
      {/* Page Header */}
      <div>
        <p className="text-muted-foreground text-sm font-medium mb-1">Overview</p>
        <h1 className="text-3xl font-bold tracking-tight" data-testid="text-page-title">
          Inspection Inbox
        </h1>
      </div>

      {/* Filters Row */}
      <div className="flex flex-wrap items-center gap-4 bg-card p-5 rounded-2xl shadow-sm border">
        {/* Status Filter */}
        <div className="flex items-center gap-2">
          <label className="text-sm font-medium text-muted-foreground">Status:</label>
          <Select value={statusFilter} onValueChange={setStatusFilter}>
            <SelectTrigger className="w-[160px]" data-testid="filter-status">
              <SelectValue placeholder="All Statuses" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">All Statuses</SelectItem>
              <SelectItem value="ASSIGNED">Draft</SelectItem>
              <SelectItem value="SUBMITTED">Submitted</SelectItem>
              <SelectItem value="REVIEWED">Reviewed</SelectItem>
              <SelectItem value="ARCHIVED">Sent to Owner</SelectItem>
            </SelectContent>
          </Select>
        </div>

        {/* Unit Filter */}
        <div className="flex items-center gap-2">
          <label className="text-sm font-medium text-muted-foreground">Unit:</label>
          <Select value={unitFilter} onValueChange={setUnitFilter}>
            <SelectTrigger className="w-[200px]" data-testid="filter-unit">
              <SelectValue placeholder="All Units" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">All Units</SelectItem>
              {unitOptions.map((unit) => (
                <SelectItem key={unit.id} value={unit.id}>
                  {unit.label}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>

        {/* Date Range */}
        <div className="flex items-center gap-2">
          <label className="text-sm font-medium text-muted-foreground">From:</label>
          <Input
            type="date"
            value={dateFrom}
            onChange={(e) => setDateFrom(e.target.value)}
            className="w-[150px]"
            data-testid="filter-date-from"
          />
        </div>

        <div className="flex items-center gap-2">
          <label className="text-sm font-medium text-muted-foreground">To:</label>
          <Input
            type="date"
            value={dateTo}
            onChange={(e) => setDateTo(e.target.value)}
            className="w-[150px]"
            data-testid="filter-date-to"
          />
        </div>

        {/* Clear Filters */}
        {(statusFilter !== "all" || unitFilter !== "all" || dateFrom || dateTo) && (
          <Button
            variant="ghost"
            size="sm"
            onClick={() => {
              setStatusFilter("all");
              setUnitFilter("all");
              setDateFrom("");
              setDateTo("");
            }}
            data-testid="button-clear-filters"
          >
            Clear Filters
          </Button>
        )}
      </div>

      {/* Inspection Inbox Table */}
      <div className="bg-card rounded-2xl shadow-sm border overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full" data-testid="table-inspection-inbox">
            <thead>
              <tr className="border-b bg-muted/30">
                <th className="px-6 py-4 text-left text-xs font-semibold text-muted-foreground uppercase tracking-wider">
                  Unit
                </th>
                <th className="px-6 py-4 text-left text-xs font-semibold text-muted-foreground uppercase tracking-wider">
                  Inspector
                </th>
                <th className="px-6 py-4 text-left text-xs font-semibold text-muted-foreground uppercase tracking-wider">
                  Type
                </th>
                <th className="px-6 py-4 text-left text-xs font-semibold text-muted-foreground uppercase tracking-wider">
                  Status
                </th>
                <th className="px-6 py-4 text-left text-xs font-semibold text-muted-foreground uppercase tracking-wider">
                  Date Submitted
                </th>
                <th className="px-6 py-4 text-right text-xs font-semibold text-muted-foreground uppercase tracking-wider">
                  Actions
                </th>
              </tr>
            </thead>
            <tbody className="divide-y divide-border">
              {isLoading ? (
                <tr>
                  <td colSpan={6} className="px-6 py-12 text-center text-muted-foreground">
                    <div className="flex items-center justify-center gap-2">
                      <div className="h-4 w-4 border-2 border-primary border-t-transparent rounded-full animate-spin" />
                      Loading inspections...
                    </div>
                  </td>
                </tr>
              ) : filteredItems.length === 0 ? (
                <tr>
                  <td colSpan={6} className="px-6 py-12 text-center text-muted-foreground">
                    No inspections found
                  </td>
                </tr>
              ) : (
                filteredItems.map((item) => (
                  <tr
                    key={`${item.sourceType}-${item.id}`}
                    className="hover:bg-muted/30 transition-colors"
                    data-testid={`row-inspection-${item.id}`}
                  >
                    {/* Unit Column */}
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-3">
                        <Avatar className="h-8 w-8">
                          <AvatarFallback className="bg-gradient-to-br from-chart-3 to-chart-5 text-white text-xs font-semibold">
                            {item.unitId ? getUnitInitial(item.unitId) : item.unitNumber.charAt(0).toUpperCase()}
                          </AvatarFallback>
                        </Avatar>
                        <span className="font-medium text-sm">
                          {item.unitNumber}
                        </span>
                      </div>
                    </td>

                    {/* Inspector Column */}
                    <td className="px-6 py-4">
                      <span className="text-sm">{getUserName(item.inspectorId)}</span>
                    </td>

                    {/* Type Column */}
                    <td className="px-6 py-4">
                      <span className="text-sm">{item.type}</span>
                    </td>

                    {/* Status Column */}
                    <td className="px-6 py-4">
                      <StatusPill status={item.status} />
                    </td>

                    {/* Date Column */}
                    <td className="px-6 py-4">
                      <span className="text-muted-foreground text-sm">
                        {formatDate(item.dateSubmitted)}
                      </span>
                    </td>

                    {/* Actions Column */}
                    <td className="px-6 py-4 text-right">
                      <ActionsDropdown
                        taskId={item.id}
                        status={item.status}
                        onView={() => handleView(item)}
                        onMarkReviewed={item.sourceType === "inspection" ? () => handleMarkReviewed(item.id) : undefined}
                        onMarkSent={item.sourceType === "inspection" ? () => handleMarkSent(item.id) : undefined}
                      />
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

client/src/pages/register.tsx.content:
import { useState } from "react";
import { Link, useLocation } from "wouter";
import { useAuth } from "@/lib/auth";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { useToast } from "@/hooks/use-toast";
import { ThemeToggle } from "@/components/theme-toggle";
import { ClipboardCheck, Loader2 } from "lucide-react";
import type { UserRole } from "@shared/schema";

export default function RegisterPage() {
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [role, setRole] = useState<UserRole>("CLEANER");
  const [isLoading, setIsLoading] = useState(false);
  const { register } = useAuth();
  const [, setLocation] = useLocation();
  const { toast } = useToast();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    try {
      await register(name, email, password, role);
      setLocation("/");
    } catch (error) {
      toast({
        variant: "destructive",
        title: "Registration Failed",
        description: error instanceof Error ? error.message : "Could not create account",
      });
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-background flex flex-col">
      <header className="fixed top-0 left-0 right-0 z-50 flex items-center justify-between p-4 border-b bg-background/95 backdrop-blur supports-[backdrop-filter]:bg-background/60">
        <div className="flex items-center gap-2">
          <ClipboardCheck className="h-6 w-6 text-primary" />
          <span className="font-semibold text-lg">TBA Inspection</span>
        </div>
        <ThemeToggle />
      </header>

      <main className="flex-1 flex items-center justify-center p-4 pt-20">
        <Card className="w-full max-w-md">
          <CardHeader className="text-center">
            <div className="mx-auto mb-4 flex h-14 w-14 items-center justify-center rounded-full bg-primary/10">
              <ClipboardCheck className="h-7 w-7 text-primary" />
            </div>
            <CardTitle className="text-2xl font-bold">Create Account</CardTitle>
            <CardDescription>Join the TBA Inspection team</CardDescription>
          </CardHeader>
          <CardContent>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="space-y-2">
                <Label htmlFor="name">Full Name</Label>
                <Input
                  id="name"
                  type="text"
                  placeholder="John Doe"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  required
                  data-testid="input-name"
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="email">Email</Label>
                <Input
                  id="email"
                  type="email"
                  placeholder="name@example.com"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  required
                  data-testid="input-email"
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="password">Password</Label>
                <Input
                  id="password"
                  type="password"
                  placeholder="Create a strong password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  required
                  minLength={6}
                  data-testid="input-password"
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="role">Role</Label>
                <Select value={role} onValueChange={(v) => setRole(v as UserRole)}>
                  <SelectTrigger data-testid="select-role">
                    <SelectValue placeholder="Select your role" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="CLEANER">Cleaner</SelectItem>
                    <SelectItem value="INSPECTOR">Inspector</SelectItem>
                    <SelectItem value="PM">Property Manager</SelectItem>
                    <SelectItem value="ADMIN">Admin</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <Button type="submit" className="w-full" disabled={isLoading} data-testid="button-register">
                {isLoading ? (
                  <>
                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                    Creating Account...
                  </>
                ) : (
                  "Create Account"
                )}
              </Button>
            </form>

            <div className="mt-6 text-center text-sm text-muted-foreground">
              Already have an account?{" "}
              <Link href="/login" className="text-primary hover:underline" data-testid="link-login">
                Sign in
              </Link>
            </div>
          </CardContent>
        </Card>
      </main>
    </div>
  );
}

