import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Skeleton } from "@/components/ui/skeleton";
import { Check, Video, Image, Download, Play, ChevronRight } from "lucide-react";
import type { Media, MediaCategory } from "@shared/schema";

interface MediaTask {
  category: MediaCategory;
  label: string;
  type: "VIDEO" | "PHOTO";
  conditional?: boolean;
}

const VIDEO_TASKS: MediaTask[] = [
  { category: "VIDEO_WALKTHROUGH", label: "Full unit walkthrough", type: "VIDEO" },
  { category: "VIDEO_ENTRANCE_ELEVATOR", label: "Entrance to elevator", type: "VIDEO" },
  { category: "VIDEO_PARKING_ENTRANCE", label: "Parking garage entrance", type: "VIDEO" },
  { category: "VIDEO_PARKING_ACCESS", label: "Access designated parking", type: "VIDEO" },
  { category: "VIDEO_THERMOSTAT", label: "Thermostat how-to", type: "VIDEO" },
  { category: "VIDEO_GARBAGE_RECYCLING", label: "Garbage/recycling access", type: "VIDEO" },
  { category: "VIDEO_SPECIAL_INSTRUCTIONS", label: "Special instructions", type: "VIDEO" },
  { category: "VIDEO_TV_DEMO", label: "TV working demo", type: "VIDEO" },
  { category: "VIDEO_BALCONY_DOORS", label: "Balcony doors", type: "VIDEO", conditional: true },
  { category: "VIDEO_WINDOWS_OPENING", label: "Windows opening", type: "VIDEO" },
];

const PHOTO_TASKS: MediaTask[] = [
  { category: "PHOTO_AC_FILTER", label: "AC filter wide angle", type: "PHOTO" },
  { category: "PHOTO_FAUCET_BRANDS", label: "Faucet brand names", type: "PHOTO" },
  { category: "PHOTO_APPLIANCE_MODELS", label: "Appliance model number stickers", type: "PHOTO" },
  { category: "PHOTO_WIFI_MODEM", label: "WiFi modem back (SSID/password)", type: "PHOTO" },
  { category: "PHOTO_FUSE_BOX", label: "Fuse box open/closed", type: "PHOTO" },
  { category: "PHOTO_VACUUM", label: "Vacuum photo", type: "PHOTO" },
  { category: "PHOTO_KEY_FOB", label: "Key/fob set", type: "PHOTO" },
  { category: "PHOTO_BALCONY_OUTDOOR", label: "Balcony/outdoor", type: "PHOTO", conditional: true },
];

const ALL_TASKS = [...VIDEO_TASKS, ...PHOTO_TASKS];

interface MediaLibraryProps {
  unitId: string;
  unitName?: string;
  compact?: boolean;
}

export function MediaLibrary({ unitId, unitName, compact = false }: MediaLibraryProps) {
  const [selectedCategory, setSelectedCategory] = useState<MediaCategory | null>(null);

  const { data: mediaItems = [], isLoading } = useQuery<Media[]>({
    queryKey: ["/api/units", unitId, "media-library"],
    enabled: !!unitId,
  });

  const mediaByCategory = mediaItems.reduce((acc, item) => {
    const cat = item.category || "OTHER";
    if (!acc[cat]) acc[cat] = [];
    acc[cat].push(item);
    return acc;
  }, {} as Record<string, Media[]>);

  const completedTasks = ALL_TASKS.filter(task => 
    mediaByCategory[task.category]?.length > 0
  );

  const totalTasks = ALL_TASKS.length;
  const completedCount = completedTasks.length;
  const completionPercent = totalTasks > 0 ? Math.round((completedCount / totalTasks) * 100) : 0;

  const selectedMedia = selectedCategory ? (mediaByCategory[selectedCategory] || []) : [];

  const handleDownload = (url: string, filename?: string) => {
    const link = document.createElement("a");
    link.href = url;
    link.download = filename || url.split("/").pop() || "media";
    link.target = "_blank";
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  if (isLoading) {
    return (
      <div className="flex gap-4 h-full">
        <div className="w-80 space-y-2">
          {Array.from({ length: 10 }).map((_, i) => (
            <Skeleton key={i} className="h-10 w-full" />
          ))}
        </div>
        <div className="flex-1">
          <Skeleton className="h-64 w-full" />
        </div>
      </div>
    );
  }

  const renderTaskList = (tasks: MediaTask[], title: string, icon: React.ReactNode) => (
    <div className="mb-4">
      <div className="flex items-center gap-2 mb-2 text-sm font-medium text-muted-foreground">
        {icon}
        <span>{title}</span>
      </div>
      <div className="space-y-1">
        {tasks.map(task => {
          const hasMedia = (mediaByCategory[task.category]?.length || 0) > 0;
          const mediaCount = mediaByCategory[task.category]?.length || 0;
          const isSelected = selectedCategory === task.category;

          return (
            <button
              key={task.category}
              onClick={() => setSelectedCategory(task.category)}
              className={`w-full flex items-center gap-2 px-3 py-2 rounded-md text-left text-sm transition-colors ${
                isSelected 
                  ? "bg-primary text-primary-foreground" 
                  : "hover-elevate"
              }`}
              data-testid={`task-${task.category}`}
            >
              <div className={`w-5 h-5 rounded-full flex items-center justify-center flex-shrink-0 ${
                hasMedia 
                  ? "bg-green-500 text-white" 
                  : "border-2 border-muted-foreground/30"
              }`}>
                {hasMedia && <Check className="w-3 h-3" />}
              </div>
              <span className="flex-1 truncate">{task.label}</span>
              {task.conditional && (
                <Badge variant="outline" className="text-xs">Optional</Badge>
              )}
              {mediaCount > 0 && (
                <Badge variant="secondary" className="text-xs">{mediaCount}</Badge>
              )}
              <ChevronRight className={`w-4 h-4 text-muted-foreground ${isSelected ? "text-primary-foreground" : ""}`} />
            </button>
          );
        })}
      </div>
    </div>
  );

  return (
    <div className={`flex gap-4 ${compact ? "h-[500px]" : "h-full min-h-[600px]"}`}>
      <Card className="w-80 flex-shrink-0 flex flex-col">
        <CardHeader className="pb-3">
          <div className="flex items-center justify-between">
            <CardTitle className="text-base" data-testid="text-media-library-title">
              {unitName ? `${unitName} Media` : "Part 1 Tasks"}
            </CardTitle>
            <Badge 
              variant={completionPercent === 100 ? "default" : "secondary"}
              data-testid="badge-completion"
            >
              {completionPercent}% complete
            </Badge>
          </div>
          <div className="text-sm text-muted-foreground">
            {completedCount} of {totalTasks} tasks completed
          </div>
        </CardHeader>
        <CardContent className="flex-1 overflow-hidden p-0">
          <ScrollArea className="h-full px-4 pb-4">
            {renderTaskList(VIDEO_TASKS, "Videos", <Video className="w-4 h-4" />)}
            {renderTaskList(PHOTO_TASKS, "Photos", <Image className="w-4 h-4" />)}
          </ScrollArea>
        </CardContent>
      </Card>

      <Card className="flex-1 flex flex-col">
        <CardHeader className="pb-3">
          <CardTitle className="text-base" data-testid="text-selected-task">
            {selectedCategory 
              ? ALL_TASKS.find(t => t.category === selectedCategory)?.label || selectedCategory
              : "Select a task to view media"
            }
          </CardTitle>
          {selectedCategory && (
            <div className="text-sm text-muted-foreground">
              {selectedMedia.length} item{selectedMedia.length !== 1 ? "s" : ""} uploaded
            </div>
          )}
        </CardHeader>
        <CardContent className="flex-1 overflow-hidden">
          {!selectedCategory ? (
            <div className="h-full flex items-center justify-center text-muted-foreground">
              <div className="text-center">
                <Video className="w-12 h-12 mx-auto mb-2 opacity-50" />
                <p>Select a task from the list to view media</p>
              </div>
            </div>
          ) : selectedMedia.length === 0 ? (
            <div className="h-full flex items-center justify-center text-muted-foreground">
              <div className="text-center">
                <Image className="w-12 h-12 mx-auto mb-2 opacity-50" />
                <p>No media uploaded for this task yet</p>
              </div>
            </div>
          ) : (
            <ScrollArea className="h-full">
              <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
                {selectedMedia.map(item => (
                  <div 
                    key={item.id} 
                    className="relative group rounded-lg overflow-hidden border bg-muted"
                    data-testid={`media-item-${item.id}`}
                  >
                    {item.type === "VIDEO" ? (
                      <div className="aspect-video bg-black flex items-center justify-center">
                        <video 
                          src={item.url} 
                          className="w-full h-full object-cover"
                          preload="metadata"
                        />
                        <div className="absolute inset-0 flex items-center justify-center">
                          <div className="w-12 h-12 rounded-full bg-black/60 flex items-center justify-center">
                            <Play className="w-6 h-6 text-white ml-1" />
                          </div>
                        </div>
                      </div>
                    ) : (
                      <div className="aspect-square">
                        <img 
                          src={item.url} 
                          alt="Inspection photo"
                          className="w-full h-full object-cover"
                        />
                      </div>
                    )}
                    <div className="absolute inset-0 bg-black/0 group-hover:bg-black/40 transition-colors flex items-center justify-center opacity-0 group-hover:opacity-100">
                      <Button 
                        size="icon" 
                        variant="secondary"
                        onClick={() => handleDownload(item.url)}
                        data-testid={`button-download-${item.id}`}
                      >
                        <Download className="w-4 h-4" />
                      </Button>
                    </div>
                    <div className="absolute bottom-0 left-0 right-0 p-2 bg-gradient-to-t from-black/60 to-transparent">
                      <div className="flex items-center gap-1 text-white text-xs">
                        {item.type === "VIDEO" ? <Video className="w-3 h-3" /> : <Image className="w-3 h-3" />}
                        <span>{item.type}</span>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </ScrollArea>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

shared/schema.ts.content:
import { sql } from "drizzle-orm";
import { pgTable, text, varchar, boolean, timestamp, pgEnum, jsonb, integer } from "drizzle-orm/pg-core";
import { createInsertSchema } from "drizzle-zod";
import { z } from "zod";

// Enums
export const userRoleEnum = pgEnum("user_role", ["CLEANER", "INSPECTOR", "PM", "ADMIN"]);
export const inspectionTypeEnum = pgEnum("inspection_type", ["FULL_INSPECTION", "ONBOARDING"]);
export const taskStatusEnum = pgEnum("task_status", ["ASSIGNED", "IN_PROGRESS", "SUBMITTED", "REVIEWED", "ARCHIVED"]);
export const checklistResultEnum = pgEnum("checklist_result", ["PASS", "FAIL", "NA", "YES", "NO", "MISSING", "NEED_REPLACEMENT", "GOOD"]);
export const severityEnum = pgEnum("severity", ["LOW", "MED", "HIGH"]);
export const mediaTypeEnum = pgEnum("media_type", ["PHOTO", "VIDEO"]);
export const quickReportStatusEnum = pgEnum("quick_report_status", ["NEW", "ACKNOWLEDGED", "RESOLVED"]);
export const damageLocationEnum = pgEnum("damage_location", ["KITCHEN", "BATHROOM", "BEDROOM", "LIVING_ROOM", "HALLWAY", "BALCONY", "EXTERIOR", "OTHER"]);
export const damageSeverityEnum = pgEnum("damage_severity", ["MINOR", "MODERATE", "SEVERE"]);
export const notificationTypeEnum = pgEnum("notification_type", ["QUICK_REPORT", "INSPECTION_SUBMITTED", "INSPECTION_ASSIGNED"]);
export const mediaCategoryEnum = pgEnum("media_category", [
  // Videos - Part 1 tasks
  "VIDEO_WALKTHROUGH",
  "VIDEO_ENTRANCE_ELEVATOR",
  "VIDEO_PARKING_ENTRANCE",
  "VIDEO_PARKING_ACCESS",
  "VIDEO_THERMOSTAT",
  "VIDEO_GARBAGE_RECYCLING",
  "VIDEO_SPECIAL_INSTRUCTIONS",
  "VIDEO_TV_DEMO",
  "VIDEO_BALCONY_DOORS",
  "VIDEO_WINDOWS_OPENING",
  // Photos - Part 1 tasks
  "PHOTO_AC_FILTER",
  "PHOTO_FAUCET_BRANDS",
  "PHOTO_APPLIANCE_MODELS",
  "PHOTO_WIFI_MODEM",
  "PHOTO_FUSE_BOX",
  "PHOTO_VACUUM",
  "PHOTO_KEY_FOB",
  "PHOTO_BALCONY_OUTDOOR",
  // Generic
  "OTHER"
]);

// Users table
export const users = pgTable("users", {
  id: varchar("id", { length: 36 }).primaryKey().default(sql`gen_random_uuid()`),
  name: text("name").notNull(),
  email: text("email").notNull().unique(),
  passwordHash: text("password_hash").notNull(),
  role: userRoleEnum("role").notNull().default("CLEANER"),
  isActive: boolean("is_active").notNull().default(true),
  createdAt: timestamp("created_at").notNull().defaultNow(),
});

// Units table
export const units = pgTable("units", {
  id: varchar("id", { length: 36 }).primaryKey().default(sql`gen_random_uuid()`),
  propertyName: text("property_name").notNull(),
  unitNumber: text("unit_number").notNull(),
  address: text("address").notNull(),
  notes: text("notes"),
  isActive: boolean("is_active").notNull().default(true),
  createdAt: timestamp("created_at").notNull().defaultNow(),
});

// Inspection templates
export const inspectionTemplates = pgTable("inspection_templates", {
  id: varchar("id", { length: 36 }).primaryKey().default(sql`gen_random_uuid()`),
  name: text("name").notNull(),
  type: inspectionTypeEnum("type").notNull(),
  rooms: jsonb("rooms").notNull().$type<TemplateRoom[]>(),
  version: integer("version").notNull().default(1),
  isActive: boolean("is_active").notNull().default(true),
  createdAt: timestamp("created_at").notNull().defaultNow(),
});

// Inspection tasks
export const inspectionTasks = pgTable("inspection_tasks", {
  id: varchar("id", { length: 36 }).primaryKey().default(sql`gen_random_uuid()`),
  type: inspectionTypeEnum("type").notNull(),
  unitId: varchar("unit_id", { length: 36 }).notNull().references(() => units.id),
  assignedToUserId: varchar("assigned_to_user_id", { length: 36 }).notNull().references(() => users.id),
  responsiblePmId: varchar("responsible_pm_id", { length: 36 }).references(() => users.id),
  templateId: varchar("template_id", { length: 36 }).references(() => inspectionTemplates.id),
  scheduledAt: timestamp("scheduled_at"),
  status: taskStatusEnum("status").notNull().default("ASSIGNED"),
  reportPdfUrl: text("report_pdf_url"),
  createdById: varchar("created_by_id", { length: 36 }).notNull().references(() => users.id),
  bedroomCount: integer("bedroom_count"),
  bathroomCount: integer("bathroom_count"),
  keySetsProvided: integer("key_sets_provided"),
  guestName: text("guest_name"),
  createdAt: timestamp("created_at").notNull().defaultNow(),
  updatedAt: timestamp("updated_at").notNull().defaultNow(),
});

// Checklist responses
export const checklistResponses = pgTable("checklist_responses", {
  id: varchar("id", { length: 36 }).primaryKey().default(sql`gen_random_uuid()`),
  inspectionTaskId: varchar("inspection_task_id", { length: 36 }).notNull().references(() => inspectionTasks.id),
  roomKey: text("room_key").notNull(),
  itemKey: text("item_key").notNull(),
  result: checklistResultEnum("result").notNull(),
  notes: text("notes"),
  severity: severityEnum("severity"),
  requiredMediaSatisfied: boolean("required_media_satisfied").notNull().default(false),
  createdAt: timestamp("created_at").notNull().defaultNow(),
});

// Media
export const media = pgTable("media", {
  id: varchar("id", { length: 36 }).primaryKey().default(sql`gen_random_uuid()`),
  inspectionTaskId: varchar("inspection_task_id", { length: 36 }).references(() => inspectionTasks.id),
  checklistResponseId: varchar("checklist_response_id", { length: 36 }).references(() => checklistResponses.id),
  quickReportId: varchar("quick_report_id", { length: 36 }),
  unitId: varchar("unit_id", { length: 36 }).references(() => units.id),
  category: mediaCategoryEnum("category"),
  type: mediaTypeEnum("type").notNull(),
  url: text("url").notNull(),
  timestampCapturedAt: timestamp("timestamp_captured_at"),
  uploadedAt: timestamp("uploaded_at").notNull().defaultNow(),
});

// Quick reports
export const quickReports = pgTable("quick_reports", {
  id: varchar("id", { length: 36 }).primaryKey().default(sql`gen_random_uuid()`),
  unitNumber: text("unit_number").notNull(),
  createdById: varchar("created_by_id", { length: 36 }).notNull().references(() => users.id),
  responsiblePmId: varchar("responsible_pm_id", { length: 36 }).notNull().references(() => users.id),
  location: damageLocationEnum("location").notNull(),
  locationDetails: text("location_details"),
  description: text("description").notNull(),
  severity: damageSeverityEnum("severity").notNull(),
  pmNotes: text("pm_notes"),
  cleaningNotes: text("cleaning_notes"),
  status: quickReportStatusEnum("status").notNull().default("NEW"),
  createdAt: timestamp("created_at").notNull().defaultNow(),
});

// Notifications
export const notifications = pgTable("notifications", {
  id: varchar("id", { length: 36 }).primaryKey().default(sql`gen_random_uuid()`),
  userId: varchar("user_id", { length: 36 }).notNull().references(() => users.id),
  type: notificationTypeEnum("type").notNull(),
  title: text("title").notNull(),
  body: text("body").notNull(),
  linkUrl: text("link_url"),
  readAt: timestamp("read_at"),
  createdAt: timestamp("created_at").notNull().defaultNow(),
});

// Email logs
export const emailLogs = pgTable("email_logs", {
  id: varchar("id", { length: 36 }).primaryKey().default(sql`gen_random_uuid()`),
  toEmail: text("to_email").notNull(),
  subject: text("subject").notNull(),
  bodyText: text("body_text").notNull(),
  relatedQuickReportId: varchar("related_quick_report_id", { length: 36 }),
  relatedInspectionTaskId: varchar("related_inspection_task_id", { length: 36 }),
  createdAt: timestamp("created_at").notNull().defaultNow(),
});

// Audit logs
export const auditLogs = pgTable("audit_logs", {
  id: varchar("id", { length: 36 }).primaryKey().default(sql`gen_random_uuid()`),
  actorUserId: varchar("actor_user_id", { length: 36 }).references(() => users.id),
  action: text("action").notNull(),
  entityType: text("entity_type").notNull(),
  entityId: text("entity_id").notNull(),
  meta: jsonb("meta").$type<Record<string, unknown>>(),
  createdAt: timestamp("created_at").notNull().defaultNow(),
});

// PM Notes (internal notes on units, visible only to PM/Admin)
export const pmNotes = pgTable("pm_notes", {
  id: varchar("id", { length: 36 }).primaryKey().default(sql`gen_random_uuid()`),
  unitId: varchar("unit_id", { length: 36 }).notNull().references(() => units.id),
  createdById: varchar("created_by_id", { length: 36 }).notNull().references(() => users.id),
  content: text("content").notNull(),
  createdAt: timestamp("created_at").notNull().defaultNow(),
  updatedAt: timestamp("updated_at").notNull().defaultNow(),
});

// Owner report enums
export const issueCategoryPriorityEnum = pgEnum("issue_category_priority", ["HIGH", "LOWER"]);
export const ownerReportStatusEnum = pgEnum("owner_report_status", ["DRAFT", "FINALIZED", "SENT"]);
export const ownerResponseEnum = pgEnum("owner_response", ["LEAVE_AS_IS", "ILL_REPLACE", "PLEASE_FIX", "PROCEED_PURCHASE"]);

// Issue Categories (global PM categories for classifying inspection findings)
export const issueCategories = pgTable("issue_categories", {
  id: varchar("id", { length: 36 }).primaryKey().default(sql`gen_random_uuid()`),
  name: text("name").notNull(),
  color: text("color").notNull().default("#6b7280"),
  sortOrder: integer("sort_order").notNull().default(0),
  isDefault: boolean("is_default").notNull().default(false),
  isActive: boolean("is_active").notNull().default(true),
  createdAt: timestamp("created_at").notNull().defaultNow(),
});

// Owner Reports (assembled from categorized inspection items)
export const ownerReports = pgTable("owner_reports", {
  id: varchar("id", { length: 36 }).primaryKey().default(sql`gen_random_uuid()`),
  inspectionTaskId: varchar("inspection_task_id", { length: 36 }).notNull().references(() => inspectionTasks.id),
  unitId: varchar("unit_id", { length: 36 }).notNull().references(() => units.id),
  createdById: varchar("created_by_id", { length: 36 }).notNull().references(() => users.id),
  ownerName: text("owner_name").notNull().default(""),
  ownerEmail: text("owner_email"),
  shareToken: text("share_token").notNull(),
  status: ownerReportStatusEnum("status").notNull().default("DRAFT"),
  amazonCartLink: text("amazon_cart_link"),
  closingMessage: text("closing_message"),
  customNotes: text("custom_notes"),
  createdAt: timestamp("created_at").notNull().defaultNow(),
  updatedAt: timestamp("updated_at").notNull().defaultNow(),
});

// Owner Report Items (individual categorized inspection items in the report)
export const ownerReportItems = pgTable("owner_report_items", {
  id: varchar("id", { length: 36 }).primaryKey().default(sql`gen_random_uuid()`),
  ownerReportId: varchar("owner_report_id", { length: 36 }).notNull().references(() => ownerReports.id),
  checklistResponseId: varchar("checklist_response_id", { length: 36 }).references(() => checklistResponses.id),
  categoryId: varchar("category_id", { length: 36 }).notNull().references(() => issueCategories.id),
  priority: issueCategoryPriorityEnum("priority").default("LOWER"),
  roomName: text("room_name").notNull(),
  itemName: text("item_name").notNull(),
  description: text("description"),
  repairQuote: text("repair_quote"),
  mediaUrls: jsonb("media_urls").$type<string[]>().default([]),
  sortOrder: integer("sort_order").notNull().default(0),
  ownerResponse: ownerResponseEnum("owner_response"),
  ownerComment: text("owner_comment"),
  ownerRespondedAt: timestamp("owner_responded_at"),
  createdAt: timestamp("created_at").notNull().defaultNow(),
});

// Form field type enum for the form builder
export const formFieldTypeEnum = pgEnum("form_field_type", [
  "RADIO_GROUP",
  "CHECKBOX",
  "DROPDOWN",
  "MULTI_SELECT",
  "FILE_UPLOAD",
  "SINGLE_LINE_INPUT",
  "LONG_TEXT",
  "AUTO_FILL",
  "CONDITION_DROPDOWN",
  "COUNT_INPUT",
  "MODEL_NUMBER",
  "LOCATION_INPUT",
  "EXISTS_TOGGLE",
  "ACTION_NEEDED",
  "ISSUE_BADGES"
]);

// Form Templates (PM-created custom inspection forms)
// Note: Using generic types for JSON columns to avoid circular reference issues with recursive InspectionBlock.children
export const formTemplates = pgTable("form_templates", {
  id: varchar("id", { length: 36 }).primaryKey().default(sql`gen_random_uuid()`),
  name: text("name").notNull(),
  type: inspectionTypeEnum("type").notNull(),
  fields: jsonb("fields").notNull().default([]), // Legacy - kept for backward compatibility
  areas: jsonb("areas").notNull().default([]), // InspectionArea[] at runtime
  unitIds: text("unit_ids").array().notNull().default([]),
  createdById: varchar("created_by_id", { length: 36 }).notNull().references(() => users.id),
  isActive: boolean("is_active").notNull().default(true),
  createdAt: timestamp("created_at").notNull().defaultNow(),
  updatedAt: timestamp("updated_at").notNull().defaultNow(),
});

// Inspection block types available for each item
export type InspectionBlockType = 
  | "CONDITION"      // Good/Fair/Damaged dropdown
  | "ACTION_NEEDED"  // None/Needs Cleaning/Needs Fixing/Needs Replacement
  | "ISSUES"         // Multi-select issue badges
  | "COUNT"          // Numeric count (total and damaged)
  | "MODEL_NUMBER"   // Model number input
  | "NOTES"          // Text notes
  | "PHOTOS_VIDEOS"  // Photo/video upload
  | "EXISTS"         // Yes/No checkbox
  // Custom form fields (generic)
  | "RADIO"          // Radio button group
  | "CHECKBOX"       // Checkbox field
  | "DROPDOWN"       // Dropdown select
  | "MULTI_SELECT"   // Multi-select field
  | "AUTO_FILL"      // Auto-fill suggestions
  | "LOCATION";      // Location input

// Inspection block within an item (can have nested children)
export interface InspectionBlock {
  id: string;
  type: InspectionBlockType;
  enabled: boolean;
  order: number;
  label?: string;
  options?: string[];
  placeholder?: string;
  trueLabel?: string;
  falseLabel?: string;
  children?: InspectionBlock[];
}

// Item within an area (e.g., Couch, TV, Sink)
export interface InspectionItem {
  id: string;
  name: string;
  blocks: InspectionBlock[];
}

// Area in the inspection template (e.g., Living Room, Kitchen)
export interface InspectionArea {
  id: string;
  name: string;
  items: InspectionItem[];
}

// Legacy support - keep FormField for backward compatibility
export interface FormField {
  id: string;
  type: FormFieldType;
  label: string;
  required: boolean;
  placeholder?: string;
  options?: string[];
  defaultValue?: string;
  helpText?: string;
  validation?: {
    min?: number;
    max?: number;
    pattern?: string;
  };
  section?: string;
}

export type FormFieldType = 
  | "RADIO_GROUP"
  | "CHECKBOX"
  | "DROPDOWN"
  | "MULTI_SELECT"
  | "FILE_UPLOAD"
  | "SINGLE_LINE_INPUT"
  | "LONG_TEXT"
  | "AUTO_FILL"
  | "CONDITION_DROPDOWN"
  | "COUNT_INPUT"
  | "MODEL_NUMBER"
  | "LOCATION_INPUT"
  | "EXISTS_TOGGLE"
  | "ACTION_NEEDED"
  | "ISSUE_BADGES";

// Template types
export interface TemplateItem {
  key: string;
  label: string;
  required: boolean;
  inputType: "PASS_FAIL" | "YES_NO" | "CONDITION";
  requiresNoteOnFail?: boolean;
  requiresMedia: boolean;
}

export interface TemplateRoom {
  key: string;
  name: string;
  items: TemplateItem[];
}

// Insert schemas
export const insertUserSchema = createInsertSchema(users).omit({
  id: true,
  createdAt: true,
});

export const insertUnitSchema = createInsertSchema(units).omit({
  id: true,
  createdAt: true,
});

export const insertInspectionTemplateSchema = createInsertSchema(inspectionTemplates).omit({
  id: true,
  createdAt: true,
});

export const insertInspectionTaskSchema = createInsertSchema(inspectionTasks).omit({
  id: true,
  createdAt: true,
  updatedAt: true,
