export default function OnboardingInspectionPage() {
  const { user } = useAuth();
  const [, setLocation] = useLocation();
  const { toast } = useToast();

  const [step, setStep] = useState<"details" | "inspection" | "complete">("details");
  const [propertyDetails, setPropertyDetails] = useState<PropertyDetails>({
    unitId: "",
    pmId: "",
    bedroomCount: 1,
    bathroomCount: 1,
    keySetsProvided: 1,
  });
  const [currentAreaIndex, setCurrentAreaIndex] = useState(0);
  const [areasData, setAreasData] = useState<AllAreasData>({});
  const [showExitDialog, setShowExitDialog] = useState(false);
  const [showValidationDialog, setShowValidationDialog] = useState(false);
  const [editingImage, setEditingImage] = useState<{ areaKey: string; itemId: string; mediaId: string; url: string; isComplementary?: boolean } | null>(null);
  const [validationErrors, setValidationErrors] = useState<Array<{ areaName: string; itemName: string }>>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const { data: units } = useQuery<Unit[]>({ queryKey: ["/api/units"] });
  const { data: pms } = useQuery<UserType[]>({ queryKey: ["/api/users/pms"] });

  const selectedUnit = units?.find(u => u.id === propertyDetails.unitId);

  const generateAreas = () => {
    const areas: { key: string; name: string; icon: React.ReactNode }[] = [
      { key: "living_room", name: "Living Room", icon: <Sofa className="h-4 w-4" /> },
      { key: "dining_room", name: "Dining Room", icon: <Utensils className="h-4 w-4" /> },
      { key: "kitchen", name: "Kitchen", icon: <Utensils className="h-4 w-4" /> },
    ];

    for (let i = 1; i <= propertyDetails.bedroomCount; i++) {
      areas.push({
        key: `bedroom_${i}`,
        name: `Bedroom ${i}`,
        icon: <BedDouble className="h-4 w-4" />,
      });
    }

    for (let i = 1; i <= propertyDetails.bathroomCount; i++) {
      areas.push({
        key: `bathroom_${i}`,
        name: `Bathroom ${i}`,
        icon: <Bath className="h-4 w-4" />,
      });
    }

    areas.push({ key: "closet", name: "Closet", icon: <Shirt className="h-4 w-4" /> });
    areas.push({ key: "appliances", name: "Appliances", icon: <Refrigerator className="h-4 w-4" /> });
    areas.push({ key: "kitchen_inventory", name: "Kitchen Inventory", icon: <Package className="h-4 w-4" /> });

    return areas;
  };

  const areas = generateAreas();
  const currentArea = areas[currentAreaIndex];

  const getAreaBaseKey = (areaKey: string): string => {
    if (areaKey.startsWith("bedroom_")) return "bedroom";
    if (areaKey.startsWith("bathroom_")) return "bathroom";
    return areaKey;
  };

  const getAreaChecklistConfig = (areaKey: string) => {
    const baseKey = getAreaBaseKey(areaKey);
    return AREA_CHECKLIST_CONFIG[baseKey] || [];
  };

  const initializeAreaData = (areaKey: string): AreaData => {
    const config = getAreaChecklistConfig(areaKey);
    return {
      checklist: config.map((item, idx) => ({
        id: `${areaKey}_${idx}`,
        name: item.name,
        condition: item.hasExistsField ? "" : "Good",
        count: item.hasCount ? 1 : undefined,
        damagedCount: item.hasCount ? 0 : undefined,
        issues: [],
        notes: "",
        actionNeeded: "None",
        media: [],
        modelNumber: item.hasModelNumber ? "" : undefined,
        exists: item.hasExistsField ? undefined : undefined,
        location: item.hasLocation ? "" : undefined,
        isRemoved: false,
      })),
      complementary: [],
      isComplete: false,
    };
  };

  useEffect(() => {
    const saved = localStorage.getItem("onboardingInspectionDraftV3");
    if (saved) {
      try {
        const data = JSON.parse(saved);
        if (data.propertyDetails) setPropertyDetails(data.propertyDetails);
        if (data.areasData) {
          const restoredAreas: AllAreasData = {};
          for (const areaKey in data.areasData) {
            restoredAreas[areaKey] = {
              ...data.areasData[areaKey],
              checklist: data.areasData[areaKey].checklist?.map((item: ChecklistItemData) => ({
                ...item,
                media: item.media?.map((m: MediaPreview & { timestamp: string | Date }) => ({
                  ...m,
                  timestamp: typeof m.timestamp === 'string' ? new Date(m.timestamp) : m.timestamp,
                })) || [],
              })) || [],
              complementary: data.areasData[areaKey].complementary?.map((item: ComplementaryItem) => ({
                ...item,
                media: item.media?.map((m: MediaPreview & { timestamp: string | Date }) => ({
                  ...m,
                  timestamp: typeof m.timestamp === 'string' ? new Date(m.timestamp) : m.timestamp,
                })) || [],
              })) || [],
            };
          }
          setAreasData(restoredAreas);
        }
        if (data.step) setStep(data.step);
        if (typeof data.currentAreaIndex === "number") setCurrentAreaIndex(data.currentAreaIndex);
      } catch (e) {
        console.error("Failed to restore draft:", e);
      }
    }
  }, []);

  useEffect(() => {
    if (step !== "complete") {
      localStorage.setItem("onboardingInspectionDraftV3", JSON.stringify({
        propertyDetails,
        areasData,
        step,
        currentAreaIndex,
      }));
    }
  }, [propertyDetails, areasData, step, currentAreaIndex]);

  const updatePropertyDetails = (field: keyof PropertyDetails, value: string | number) => {
    setPropertyDetails(prev => ({ ...prev, [field]: value }));
  };

  const ensureAreaInitialized = (areaKey: string) => {
    if (!areasData[areaKey]) {
      setAreasData(prev => ({
        ...prev,
        [areaKey]: initializeAreaData(areaKey),
      }));
    }
  };

  const isAreaComplete = (areaKey: string): boolean => {
    const data = areasData[areaKey];
    if (!data) return false;
    const config = getAreaChecklistConfig(areaKey);
    const allItemsDocumented = data.checklist.every((item, idx) => {
      if (item.isRemoved) return true;
      const itemConfig = config[idx];
      if (itemConfig?.hasExistsField) {
        return item.exists !== undefined;
      }
      return item.condition && item.condition !== "";
    });
    return allItemsDocumented && data.checklist.length > 0;
  };

  const getUnfilledItems = (): Array<{ areaName: string; itemName: string }> => {
    const unfilled: Array<{ areaName: string; itemName: string }> = [];
    areas.forEach(area => {
      const data = areasData[area.key];
      const config = getAreaChecklistConfig(area.key);
      if (data?.checklist) {
        data.checklist.forEach((item, idx) => {
          if (item.isRemoved) return;
          const itemConfig = config[idx];
          if (itemConfig?.hasExistsField) {
            if (item.exists === undefined) {
              unfilled.push({ areaName: area.name, itemName: item.name });
            }
          } else {
            if (!item.condition || item.condition === "") {
              unfilled.push({ areaName: area.name, itemName: item.name });
            }
          }
        });
      }
    });
    return unfilled;
  };

  const updateChecklistItem = (areaKey: string, itemId: string, updates: Partial<ChecklistItemData>) => {
    setAreasData(prev => ({
      ...prev,
      [areaKey]: {
        ...prev[areaKey],
        checklist: prev[areaKey]?.checklist.map(item =>
          item.id === itemId ? { ...item, ...updates } : item
        ) || [],
      },
    }));
  };

  const addMediaToChecklistItem = (areaKey: string, itemId: string, media: MediaPreview) => {
    setAreasData(prev => ({
      ...prev,
      [areaKey]: {
        ...prev[areaKey],
        checklist: prev[areaKey]?.checklist.map(item =>
          item.id === itemId ? { ...item, media: [...item.media, media] } : item
        ) || [],
      },
    }));
  };

  const removeMediaFromChecklistItem = (areaKey: string, itemId: string, mediaId: string) => {
    const item = areasData[areaKey]?.checklist.find(i => i.id === itemId);
    const media = item?.media.find(m => m.id === mediaId);
    if (media) URL.revokeObjectURL(media.url);

    setAreasData(prev => ({
      ...prev,
      [areaKey]: {
        ...prev[areaKey],
        checklist: prev[areaKey]?.checklist.map(item =>
          item.id === itemId ? { ...item, media: item.media.filter(m => m.id !== mediaId) } : item
        ) || [],
      },
    }));
  };

  const handleSaveEditedImage = (editedFile: File) => {
    if (!editingImage) return;
    const { areaKey, itemId, mediaId, isComplementary } = editingImage;
    const newUrl = URL.createObjectURL(editedFile);

    if (isComplementary) {
      setAreasData(prev => ({
        ...prev,
        [areaKey]: {
          ...prev[areaKey],
          complementary: (prev[areaKey]?.complementary || []).map((item: ComplementaryItem) =>
            item.id === itemId ? {
              ...item,
              media: item.media.map((m: MediaPreview) => {
                if (m.id === mediaId) {
                  URL.revokeObjectURL(m.url);
                  return { ...m, file: editedFile, url: newUrl };
                }
                return m;
              }),
            } : item
          ),
        },
      }));
    } else {
      setAreasData(prev => ({
        ...prev,
        [areaKey]: {
          ...prev[areaKey],
          checklist: prev[areaKey]?.checklist.map(item =>
            item.id === itemId ? {
              ...item,
              media: item.media.map(m => {
                if (m.id === mediaId) {
                  URL.revokeObjectURL(m.url);
                  return { ...m, file: editedFile, url: newUrl };
                }
                return m;
              }),
            } : item
          ) || [],
        },
      }));
    }
    setEditingImage(null);
  };

  const addComplementaryItem = (areaKey: string) => {
    setAreasData(prev => ({
      ...prev,
      [areaKey]: {
        ...prev[areaKey],
        complementary: [
          ...(prev[areaKey]?.complementary || []),
          {
            id: Math.random().toString(36).slice(2),
            description: "",
            notes: "",
            media: [],
          },
        ],
      },
    }));
  };

  const updateComplementaryItem = (areaKey: string, itemId: string, updates: Partial<ComplementaryItem>) => {
    setAreasData(prev => ({
      ...prev,
      [areaKey]: {
        ...prev[areaKey],
        complementary: prev[areaKey]?.complementary.map(item =>
          item.id === itemId ? { ...item, ...updates } : item
        ) || [],
      },
    }));
  };

  const removeComplementaryItem = (areaKey: string, itemId: string) => {
    const item = areasData[areaKey]?.complementary.find(i => i.id === itemId);
    item?.media.forEach(m => URL.revokeObjectURL(m.url));
    setAreasData(prev => ({
      ...prev,
      [areaKey]: {
        ...prev[areaKey],
        complementary: prev[areaKey]?.complementary.filter(item => item.id !== itemId) || [],
      },
    }));
  };

  const testFillAllAreas = () => {
    const sampleConditions = ["Good", "Good", "Good", "Good", "Fair", "Fair", "Good", "Stained", "Good", "Damaged", "Good", "Good", "Worn", "Good", "Good"];
    const sampleNotes = [
      "", "", "", "Minor wear", "", "Light scratches visible", "", "", "Some discoloration", "",
      "Functioning well", "", "", "Needs attention", "", "Previously repaired", "",
    ];
    const sampleModelNumbers = [
      "LG-WM3900HBA", "Samsung-RF28R7551SR", "Bosch-SHP878ZD5N", "GE-JB655SKSS",
      "Whirlpool-WTW5000DW", "KitchenAid-KRMF706ESS", "Breville-BES870XL", "Moen-7594SRS",
    ];
    let modelIdx = 0;
    let condIdx = 0;
    let noteIdx = 0;

    const filledAreas: AllAreasData = {};
    areas.forEach(area => {
      const config = getAreaChecklistConfig(area.key);
      filledAreas[area.key] = {
        checklist: config.map((itemConfig, idx) => {
          const cond = itemConfig.hasExistsField ? "Good" : sampleConditions[condIdx++ % sampleConditions.length];
          const existsVal = itemConfig.hasExistsField ? true : undefined;
          const issues: string[] = [];
          if (cond !== "Good" && itemConfig.issues.length > 0) {
            issues.push(itemConfig.issues[0]);
          }
          const note = sampleNotes[noteIdx++ % sampleNotes.length];
          const actionNeeded = cond === "Good" ? "None" : (cond === "Damaged" ? "Needs Replacement" : "Needs Cleaning");
          return {
            id: `${area.key}_${idx}`,
            name: itemConfig.name,
            condition: cond,
            count: itemConfig.hasCount ? (2 + (idx % 4)) : undefined,
            damagedCount: itemConfig.hasCount ? (cond !== "Good" ? 1 : 0) : undefined,
            issues,
            notes: note,
            actionNeeded,
            media: [],
            modelNumber: itemConfig.hasModelNumber ? sampleModelNumbers[modelIdx++ % sampleModelNumbers.length] : undefined,
            exists: existsVal,
            location: itemConfig.hasLocation ? "Main hallway" : undefined,
            isRemoved: false,
          };
        }),
        complementary: [],
        isComplete: true,
      };
    });
    setAreasData(filledAreas);
    toast({ title: "Test Fill Complete", description: "All areas have been filled with sample data" });
  };

  const canStartInspection = propertyDetails.unitId && propertyDetails.pmId && propertyDetails.bedroomCount > 0 && propertyDetails.bathroomCount > 0;

  const allAreasComplete = areas.every(area => isAreaComplete(area.key));

  const handleStartInspection = () => {
    if (!canStartInspection) return;
    areas.forEach(area => ensureAreaInitialized(area.key));
    setStep("inspection");
  };

  const handleBackToDetails = () => {
    setStep("details");
  };

  const handleNavigateToArea = (index: number) => {
    ensureAreaInitialized(areas[index].key);
    setCurrentAreaIndex(index);
    window.scrollTo(0, 0);
  };

  const submitMutation = useMutation({
    mutationFn: async () => {
      const formData = new FormData();
      formData.append("unitId", propertyDetails.unitId);
      formData.append("responsiblePmId", propertyDetails.pmId);
      formData.append("createdById", user?.id || "");
      formData.append("type", "ONBOARDING");
      formData.append("bedroomCount", propertyDetails.bedroomCount.toString());
      formData.append("bathroomCount", propertyDetails.bathroomCount.toString());
      formData.append("keySetsProvided", propertyDetails.keySetsProvided.toString());

      const checklistData: Array<{
        roomKey: string;
        itemKey: string;
        result: ChecklistResult;
        notes?: string;
        severity?: Severity;
        mediaIndices: number[];
      }> = [];

      let mediaIndex = 0;

      areas.forEach(area => {
        const areaData = areasData[area.key];
        if (areaData?.checklist) {
          areaData.checklist.forEach((item) => {
            if (item.condition !== "Good" || item.issues.length > 0 || item.notes || item.media.length > 0) {
              const mediaIndices: number[] = [];
              item.media.forEach(m => {
                formData.append(`media_${mediaIndex}`, m.file);
                formData.append(`mediaType_${mediaIndex}`, m.type);
                formData.append(`mediaTimestamp_${mediaIndex}`, m.timestamp.toISOString());
                mediaIndices.push(mediaIndex);
                mediaIndex++;
              });

              const countInfo = item.count !== undefined ? `Count: ${item.count}, Damaged: ${item.damagedCount || 0}. ` : "";
              const issuesInfo = item.issues.length > 0 ? `Issues: ${item.issues.join(", ")}. ` : "";
              const actionInfo = item.actionNeeded && item.actionNeeded !== "None" ? `Action: ${item.actionNeeded}. ` : "";
              const notesInfo = item.notes ? `Notes: ${item.notes}` : "";

              checklistData.push({
                roomKey: area.key,
                itemKey: item.name.toLowerCase().replace(/\s+/g, "_"),
                result: item.condition === "Good" ? "GOOD" as ChecklistResult : "FAIL" as ChecklistResult,
                notes: `Condition: ${item.condition}. ${countInfo}${issuesInfo}${actionInfo}${notesInfo}`.trim(),
                severity: item.condition === "Good" ? undefined : "MED",
                mediaIndices,
              });
            }
          });
        }

        if (areaData?.complementary) {
          areaData.complementary.forEach((item, idx) => {
            if (item.description) {
              const mediaIndices: number[] = [];
              item.media.forEach(m => {
                formData.append(`media_${mediaIndex}`, m.file);
                formData.append(`mediaType_${mediaIndex}`, m.type);
                formData.append(`mediaTimestamp_${mediaIndex}`, m.timestamp.toISOString());
                mediaIndices.push(mediaIndex);
                mediaIndex++;
              });

              checklistData.push({
                roomKey: area.key,
                itemKey: `complementary_${idx}`,
                result: "FAIL" as ChecklistResult,
                notes: `${item.description}${item.notes ? `. Notes: ${item.notes}` : ""}`,
                severity: "MED",
                mediaIndices,
              });
            }
          });
        }
      });

      formData.append("checklistData", JSON.stringify(checklistData));
      formData.append("issuesData", JSON.stringify([]));
      formData.append("mediaCount", mediaIndex.toString());

      const token = localStorage.getItem("jwt_token");
      const headers: Record<string, string> = {};
      if (token) headers["Authorization"] = `Bearer ${token}`;

      const res = await fetch("/api/inspections/onboarding", {
        method: "POST",
        body: formData,
        headers,
        credentials: "include",
      });
      if (!res.ok) {
        const error = await res.json();
        throw new Error(error.message || "Submission failed");
      }
      return res.json();
    },
    onSuccess: () => {
      localStorage.removeItem("onboardingInspectionDraftV3");
      queryClient.invalidateQueries({ queryKey: ["/api/inspection-tasks"] });
      setStep("complete");
    },
    onError: (error) => {
      toast({
        variant: "destructive",
        title: "Submission Failed",
        description: error instanceof Error ? error.message : "Could not submit inspection",
      });
    },
  });

  const handleSubmit = async () => {
    const unfilled = getUnfilledItems();
    if (unfilled.length > 0) {
      setValidationErrors(unfilled);
      setShowValidationDialog(true);
      return;
    }

    setIsSubmitting(true);
    try {
      await submitMutation.mutateAsync();
    } finally {
      setIsSubmitting(false);
    }
  };

  if (step === "complete") {
    return (
      <div className="min-h-screen bg-background flex flex-col items-center justify-center p-4">
        <div className="text-center space-y-4">
          <div className="mx-auto w-20 h-20 rounded-full bg-chart-2/20 flex items-center justify-center">
            <CheckCircle2 className="h-10 w-10 text-chart-2" />
          </div>
          <h1 className="text-2xl font-bold">Onboarding Complete!</h1>
          <p className="text-muted-foreground">Report has been generated and sent to the PM.</p>
          <Button onClick={() => setLocation("/home")} data-testid="button-done">
            Return Home
          </Button>
        </div>
      </div>
    );
  }

  if (step === "details") {
    return (
      <div className="min-h-screen bg-background flex flex-col">
        <header className="sticky top-0 z-50 flex items-center gap-4 p-4 border-b bg-background/95 backdrop-blur">
          <Button variant="ghost" size="icon" onClick={() => setLocation("/home")} data-testid="button-back">
            <ArrowLeft className="h-5 w-5" />
          </Button>
          <div className="flex-1">
            <h1 className="font-semibold text-lg">Onboarding Inspection</h1>
            <p className="text-xs text-muted-foreground">Property Details</p>
          </div>
          <ThemeToggle />
        </header>

        <main className="flex-1 p-4 pb-24 space-y-4">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <MapPin className="h-5 w-5 text-primary" />
                Property Assignment
              </CardTitle>
              <CardDescription>Select the property and PM for this inspection</CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="space-y-2">
                <Label>Property <span className="text-destructive">*</span></Label>
                <Select value={propertyDetails.unitId} onValueChange={(v) => updatePropertyDetails("unitId", v)}>
                  <SelectTrigger data-testid="select-unit">
                    <SelectValue placeholder="Select property" />
                  </SelectTrigger>
                  <SelectContent>
                    {units?.map((unit) => (
                      <SelectItem key={unit.id} value={unit.id}>
                        {unit.propertyName} - {unit.unitNumber}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              {selectedUnit && (
                <div className="p-3 rounded-lg bg-muted/50 text-sm">
                  <p className="font-medium">{selectedUnit.propertyName}</p>
                  <p className="text-muted-foreground">{selectedUnit.address}</p>
                </div>
              )}

              <div className="space-y-2">
                <Label>Assigned PM <span className="text-destructive">*</span></Label>
                <Select value={propertyDetails.pmId} onValueChange={(v) => updatePropertyDetails("pmId", v)}>
                  <SelectTrigger data-testid="select-pm">
                    <SelectValue placeholder="Select PM" />
                  </SelectTrigger>
                  <SelectContent>
                    {pms?.map((pm) => (
                      <SelectItem key={pm.id} value={pm.id}>
                        {pm.name}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Home className="h-5 w-5 text-primary" />
                Property Configuration
              </CardTitle>
              <CardDescription>Set up the property layout</CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label className="flex items-center gap-2">
                    <BedDouble className="h-4 w-4" />
                    Bedrooms <span className="text-destructive">*</span>
                  </Label>
                  <Select 
                    value={propertyDetails.bedroomCount.toString()} 
                    onValueChange={(v) => updatePropertyDetails("bedroomCount", parseInt(v))}
                  >
                    <SelectTrigger data-testid="select-bedrooms">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      {[1, 2, 3, 4, 5].map((n) => (
                        <SelectItem key={n} value={n.toString()}>{n}</SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>

                <div className="space-y-2">
                  <Label className="flex items-center gap-2">
                    <Bath className="h-4 w-4" />
                    Bathrooms <span className="text-destructive">*</span>
                  </Label>
                  <Select 
                    value={propertyDetails.bathroomCount.toString()} 
                    onValueChange={(v) => updatePropertyDetails("bathroomCount", parseInt(v))}
                  >
                    <SelectTrigger data-testid="select-bathrooms">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      {[1, 2, 3, 4].map((n) => (
                        <SelectItem key={n} value={n.toString()}>{n}</SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
              </div>

              <div className="space-y-2">
                <Label className="flex items-center gap-2">
                  <Key className="h-4 w-4" />
                  Sets of Keys
                </Label>
                <Select 
                  value={propertyDetails.keySetsProvided.toString()} 
                  onValueChange={(v) => updatePropertyDetails("keySetsProvided", parseInt(v))}
                >
                  <SelectTrigger data-testid="select-keys">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {[1, 2, 3, 4, 5].map((n) => (
                      <SelectItem key={n} value={n.toString()}>{n}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

            </CardContent>
          </Card>
        </main>

        <div className="fixed bottom-0 left-0 right-0 p-4 bg-background border-t">
          <div className="flex gap-3 max-w-lg mx-auto">
            <Button 
              variant="outline" 
              className="flex-1"
              onClick={() => setLocation("/home")}
              data-testid="button-cancel"
            >
              Cancel
            </Button>
            <Button 
              className="flex-1"
              disabled={!canStartInspection}
              onClick={handleStartInspection}
              data-testid="button-start"
            >
              Start Inspection
              <ArrowRight className="ml-2 h-4 w-4" />
            </Button>
          </div>
        </div>
      </div>
    );
  }

  const currentAreaData = areasData[currentArea?.key] || initializeAreaData(currentArea?.key || "");
  const checklistConfig = getAreaChecklistConfig(currentArea?.key || "");

  const removeChecklistItem = (areaKey: string, itemId: string) => {
    setAreasData(prev => ({
      ...prev,
      [areaKey]: {
        ...prev[areaKey],
        checklist: prev[areaKey]?.checklist.map(item =>
          item.id === itemId ? { ...item, isRemoved: true } : item
        ) || [],
      },
    }));
  };

  const ChecklistItemCard = ({ item, config }: { item: ChecklistItemData; config: ChecklistItemConfig }) => {
    const fileInputRef = useRef<HTMLInputElement>(null);

    if (item.isRemoved) return null;

    const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
      const files = e.target.files;
      if (!files) return;

      Array.from(files).forEach(file => {
        const isVideo = file.type.startsWith("video/");
        const media: MediaPreview = {
          id: Math.random().toString(36).slice(2),
          file,
          type: isVideo ? "VIDEO" : "PHOTO",
          url: URL.createObjectURL(file),
          timestamp: new Date(),
        };
        addMediaToChecklistItem(currentArea.key, item.id, media);
      });

      if (fileInputRef.current) fileInputRef.current.value = "";
    };

    const toggleIssue = (issue: string) => {
      const newIssues = item.issues.includes(issue)
        ? item.issues.filter(i => i !== issue)
        : [...item.issues, issue];
      updateChecklistItem(currentArea.key, item.id, { issues: newIssues });
    };

    const hasIssues = item.condition !== "Good" || item.issues.length > 0 || item.notes || item.media.length > 0;
    const canRemove = config.isRemovable && !config.isCoreItem;
    const showExistsField = config.hasExistsField;
    const itemExists = item.exists !== false;

    return (
      <Card className={cn("transition-all relative", hasIssues && "border-chart-4/50 bg-chart-4/5")}>
        {canRemove && (
          <button
            className="absolute top-3 right-3 h-6 w-6 rounded-full bg-muted/80 hover:bg-destructive/10 flex items-center justify-center text-muted-foreground hover:text-destructive transition-colors"
            onClick={() => removeChecklistItem(currentArea.key, item.id)}
            data-testid={`button-remove-${item.id}`}
            title="Remove item"
          >
            <X className="h-3.5 w-3.5" />
          </button>
        )}
        <CardContent className={cn("p-4 space-y-4", canRemove && "pr-10")}>
          <div className="flex items-start justify-between gap-2">
            <div className="flex items-center gap-2">
              {config.section && (
                <Badge variant="outline" className="text-xs">{config.section}</Badge>
              )}
              <h3 className="font-semibold">{item.name}</h3>
            </div>
            {hasIssues && <Badge variant="secondary" className="bg-chart-4/20 text-chart-4">Has Notes</Badge>}
          </div>

          {showExistsField && (
            <div className="space-y-1.5">
              <Label className="text-xs text-muted-foreground">Present in Unit?</Label>
              <div className="flex gap-2">
                <Button
                  variant={item.exists === true ? "default" : "outline"}
                  size="sm"
                  onClick={() => updateChecklistItem(currentArea.key, item.id, { exists: true, condition: item.condition || "Good" })}
                  className="flex-1"
                >
                  Yes
                </Button>
                <Button
                  variant={item.exists === false ? "default" : "outline"}
                  size="sm"
                  onClick={() => updateChecklistItem(currentArea.key, item.id, { exists: false, condition: "N/A" })}
                  className="flex-1"
                >
                  No
                </Button>
              </div>
            </div>
          )}

          {itemExists && (
            <>
              <div className="grid grid-cols-2 gap-3">
                <div className="space-y-1.5">
                  <Label className="text-xs text-muted-foreground">Condition</Label>
                  <Select 
                    value={item.condition} 
                    onValueChange={(v) => updateChecklistItem(currentArea.key, item.id, { condition: v })}
                  >
                    <SelectTrigger className="h-9">
                      <SelectValue placeholder="Select condition" />
                    </SelectTrigger>
                    <SelectContent>
                      {CONDITIONS.map(c => (
                        <SelectItem key={c} value={c}>{c}</SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>

                <div className="space-y-1.5">
                  <Label className="text-xs text-muted-foreground">Action Needed</Label>
                  <Select 
                    value={item.actionNeeded} 
                    onValueChange={(v) => updateChecklistItem(currentArea.key, item.id, { actionNeeded: v })}
                  >
                    <SelectTrigger className="h-9">
                      <SelectValue placeholder="None" />
                    </SelectTrigger>
                    <SelectContent>
                      {ACTIONS_NEEDED.map(a => (
                        <SelectItem key={a} value={a}>{a}</SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
              </div>

              {config.hasModelNumber && (
                <div className="space-y-1.5">
                  <Label className="text-xs text-muted-foreground">Model Number</Label>
                  <Input 
                    placeholder="Enter model number..."
                    value={item.modelNumber || ""}
                    onChange={(e) => updateChecklistItem(currentArea.key, item.id, { modelNumber: e.target.value })}
                    className="h-9"
                    data-testid={`input-model-${item.id}`}
                  />
                </div>
              )}

              {config.hasLocation && (
                <div className="space-y-1.5">
                  <Label className="text-xs text-muted-foreground">Location</Label>
                  <Input 
                    placeholder="Enter location..."
                    value={item.location || ""}
                    onChange={(e) => updateChecklistItem(currentArea.key, item.id, { location: e.target.value })}
                    className="h-9"
                    data-testid={`input-location-${item.id}`}
                  />
                </div>
              )}

              {config.hasCount && (
                <div className="grid grid-cols-2 gap-3">
                  <div className="space-y-1.5">
                    <Label className="text-xs text-muted-foreground">Total Count</Label>
                    <Input 
                      type="number" 
                      min="0" 
                      value={item.count || 0}
                      onChange={(e) => updateChecklistItem(currentArea.key, item.id, { count: parseInt(e.target.value) || 0 })}
                      className="h-9"
                    />
                  </div>
                  <div className="space-y-1.5">
                    <Label className="text-xs text-muted-foreground">Damaged Count</Label>
                    <Input 
                      type="number" 
                      min="0" 
                      max={item.count || 0}
                      value={item.damagedCount || 0}
                      onChange={(e) => updateChecklistItem(currentArea.key, item.id, { damagedCount: parseInt(e.target.value) || 0 })}
                      className="h-9"
                    />
                  </div>
                </div>
              )}

              <div className="space-y-1.5">
                <Label className="text-xs text-muted-foreground">Issues (select all that apply)</Label>
                <div className="flex flex-wrap gap-1.5">
                  {config.issues.map(issue => (
                    <Badge
                      key={issue}
                      variant={item.issues.includes(issue) ? "default" : "outline"}
                      className={cn(
                        "cursor-pointer text-xs",
                        item.issues.includes(issue) && "bg-primary"
                      )}
                      onClick={() => toggleIssue(issue)}
                    >
                      {issue}
                    </Badge>
                  ))}
                </div>
              </div>

              {item.condition !== "Good" && (
                <div className="space-y-1.5">
                  <Label className="text-xs text-muted-foreground">Notes (describe the issue)</Label>
                  <Textarea
                    placeholder="Describe what's happening..."
                    value={item.notes || ""}
                    onChange={(e) => {
                      e.stopPropagation();
                      updateChecklistItem(currentArea.key, item.id, { notes: e.target.value });
                    }}
                    onClick={(e) => e.stopPropagation()}
                    className="min-h-[60px] resize-none"
                    data-testid={`textarea-notes-${item.id}`}
                  />
                </div>
              )}

              <div className="space-y-2">
                <div className="flex items-center justify-between">
                  <Label className="text-xs text-muted-foreground">Photos/Videos</Label>
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => fileInputRef.current?.click()}
                    className="h-8"
                  >
                    <Camera className="h-3.5 w-3.5 mr-1.5" />
                    Add Media
                  </Button>
                  <input
                    ref={fileInputRef}
                    type="file"
                    accept="image/*,video/*"
                    capture="environment"
                    multiple
                    className="hidden"
                    onChange={handleFileSelect}
                  />
                </div>

                {item.media.length > 0 && (
                  <div className="flex flex-wrap gap-2">
                    {item.media.map(m => (
                      <div key={m.id} className="relative group">
                        {m.type === "VIDEO" ? (
                          <video src={m.url} className="w-16 h-16 object-cover rounded-lg" />
                        ) : (
                          <img
                            src={m.url}
                            alt=""
                            className="w-16 h-16 object-cover rounded-lg cursor-pointer"
                            onClick={() => setEditingImage({ areaKey: currentArea.key, itemId: item.id, mediaId: m.id, url: m.url })}
                          />
                        )}
                        <button
                          onClick={() => removeMediaFromChecklistItem(currentArea.key, item.id, m.id)}
                          className="absolute -top-1.5 -right-1.5 w-5 h-5 bg-destructive text-destructive-foreground rounded-full flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity"
                        >
                          <X className="h-3 w-3" />
                        </button>
                        {m.type === "PHOTO" && (
                          <button
                            onClick={() => setEditingImage({ areaKey: currentArea.key, itemId: item.id, mediaId: m.id, url: m.url })}
                            className="absolute -top-1.5 -left-1.5 w-5 h-5 bg-black/60 text-white rounded-full flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity"
                          >
                            <Pencil className="h-2.5 w-2.5" />
                          </button>
                        )}
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </>
          )}
        </CardContent>
      </Card>
    );
  };

  const ComplementaryItemCard = ({ item }: { item: ComplementaryItem }) => {
    const fileInputRef = useRef<HTMLInputElement>(null);

    const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
      const files = e.target.files;
      if (!files) return;

      Array.from(files).forEach(file => {
        const isVideo = file.type.startsWith("video/");
        const media: MediaPreview = {
          id: Math.random().toString(36).slice(2),
          file,
          type: isVideo ? "VIDEO" : "PHOTO",
          url: URL.createObjectURL(file),
          timestamp: new Date(),
        };
        updateComplementaryItem(currentArea.key, item.id, { media: [...item.media, media] });
      });

      if (fileInputRef.current) fileInputRef.current.value = "";
    };

    return (
      <Card className="border-dashed">
        <CardContent className="p-4 space-y-3">
          <div className="flex items-center justify-between">
            <Label className="text-sm font-medium">Unlisted Item</Label>
            <Button
              variant="ghost"
              size="icon"
              className="h-7 w-7 text-destructive"
              onClick={() => removeComplementaryItem(currentArea.key, item.id)}
            >
              <Trash2 className="h-4 w-4" />
            </Button>
          </div>

          <Input
            placeholder="Describe the item..."
            value={item.description || ""}
            onChange={(e) => {
              e.stopPropagation();
              updateComplementaryItem(currentArea.key, item.id, { description: e.target.value });
            }}
            onClick={(e) => e.stopPropagation()}
          />

          <Textarea
            placeholder="Add notes..."
            value={item.notes || ""}
            onChange={(e) => {
              e.stopPropagation();
              updateComplementaryItem(currentArea.key, item.id, { notes: e.target.value });
            }}
            onClick={(e) => e.stopPropagation()}
            className="min-h-[60px] resize-none"
          />

          <div className="flex items-center gap-2">
            <Button
              variant="outline"
              size="sm"
              onClick={() => fileInputRef.current?.click()}
              className="h-8"
            >
              <Camera className="h-3.5 w-3.5 mr-1.5" />
              Add Media
            </Button>
            <input
              ref={fileInputRef}
              type="file"
              accept="image/*,video/*"
              multiple
              className="hidden"
              onChange={handleFileSelect}
            />

            {item.media.length > 0 && (
              <div className="flex gap-1.5">
                {item.media.map(m => (
                  <div key={m.id} className="relative group">
                    {m.type === "VIDEO" ? (
                      <video src={m.url} className="w-10 h-10 object-cover rounded" />
                    ) : (
                      <img
                        src={m.url}
                        alt=""
                        className="w-10 h-10 object-cover rounded cursor-pointer"
                        onClick={() => setEditingImage({ areaKey: currentArea.key, itemId: item.id, mediaId: m.id, url: m.url, isComplementary: true })}
                      />
                    )}
                    {m.type === "PHOTO" && (
                      <button
                        onClick={() => setEditingImage({ areaKey: currentArea.key, itemId: item.id, mediaId: m.id, url: m.url, isComplementary: true })}
                        className="absolute -top-1 -left-1 w-4 h-4 bg-black/60 text-white rounded-full flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity"
                      >
                        <Pencil className="h-2 w-2" />
                      </button>
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>
        </CardContent>
      </Card>
    );
  };

  return (
    <div className="min-h-screen bg-background flex flex-col lg:flex-row">
      <aside className="hidden lg:flex flex-col w-64 border-r bg-card fixed top-0 left-0 h-screen z-40">
        <div className="p-4 border-b">
          <Button variant="ghost" size="sm" onClick={handleBackToDetails} className="mb-2" data-testid="button-edit-details">
            <Settings className="h-4 w-4 mr-2" />
            Edit Property Details
          </Button>
          <h2 className="font-semibold text-lg">Areas</h2>
          <p className="text-xs text-muted-foreground">
            {areas.filter(a => isAreaComplete(a.key)).length} of {areas.length} documented
          </p>
        </div>
        <ScrollArea className="flex-1">
          <div className="p-2 space-y-1">
            {areas.map((area, idx) => (
              <button
                key={area.key}
                onClick={() => handleNavigateToArea(idx)}
                className={cn(
                  "w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-left transition-colors",
                  currentAreaIndex === idx
                    ? "bg-primary text-primary-foreground"
                    : "hover:bg-muted"
                )}
                data-testid={`nav-area-${area.key}`}
              >
                {area.icon}
                <span className="flex-1 text-sm font-medium">{area.name}</span>
                {isAreaComplete(area.key) && (
                  <CheckCircle2 className={cn(
                    "h-4 w-4",
                    currentAreaIndex === idx ? "text-primary-foreground" : "text-chart-2"
                  )} />
                )}
              </button>
            ))}
          </div>
        </ScrollArea>
        <div className="p-4 border-t space-y-2">
          <Button 
            className="w-full"
            variant="outline"
            onClick={testFillAllAreas}
            data-testid="button-test-fill"
          >
            <Lightbulb className="h-4 w-4 mr-2" />
            Test Fill All
          </Button>
          <Button 
            className="w-full" 
            variant={allAreasComplete ? "default" : "outline"}
            onClick={handleSubmit}
            disabled={isSubmitting}
            data-testid="button-submit-sidebar"
          >
            {isSubmitting ? (
              <>
                <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                Submitting...
              </>
            ) : (
              "Submit Inspection"
            )}
          </Button>
        </div>
      </aside>

      <div className="flex-1 flex flex-col lg:ml-64">
        <header className="sticky top-0 z-50 flex items-center gap-2 p-4 border-b bg-background/95 backdrop-blur lg:hidden">
          <Button variant="ghost" size="icon" onClick={() => setShowExitDialog(true)} data-testid="button-exit">
            <X className="h-5 w-5" />
          </Button>
          <div className="flex-1">
            <h1 className="font-semibold">{currentArea?.name}</h1>
            <p className="text-xs text-muted-foreground">
              Area {currentAreaIndex + 1} of {areas.length}
            </p>
          </div>
          <Button variant="outline" size="sm" onClick={testFillAllAreas} data-testid="button-test-fill-mobile">
            <Lightbulb className="h-4 w-4" />
          </Button>
          <Button variant="outline" size="sm" onClick={handleBackToDetails}>
            <Settings className="h-4 w-4" />
          </Button>
          <ThemeToggle />
        </header>

        <div className="lg:hidden overflow-x-auto border-b bg-muted/30">
          <div className="flex p-2 gap-1 min-w-max">
            {areas.map((area, idx) => (
              <button
                key={area.key}
                onClick={() => handleNavigateToArea(idx)}
                className={cn(
                  "flex items-center gap-2 px-3 py-2 rounded-lg text-sm font-medium whitespace-nowrap transition-colors",
                  currentAreaIndex === idx
                    ? "bg-primary text-primary-foreground"
                    : "bg-background hover:bg-muted"
                )}
              >
                {area.icon}
                {area.name}
                {isAreaComplete(area.key) && (
                  <CheckCircle2 className={cn(
                    "h-3.5 w-3.5",
                    currentAreaIndex === idx ? "text-primary-foreground" : "text-chart-2"
                  )} />
                )}
              </button>
            ))}
          </div>
        </div>

        <main className="flex-1 p-6 pb-32 lg:pb-8 overflow-auto">
          <div className="space-y-4">
            <div className="hidden lg:block mb-6">
              <h1 className="text-2xl font-bold">{currentArea?.name}</h1>
              <p className="text-muted-foreground">Document the condition of items in this area</p>
            </div>

            {currentAreaData.checklist.map((item, idx) => {
              const config = checklistConfig[idx];
              if (!config) return null;
              return <ChecklistItemCard key={item.id} item={item} config={config} />;
            })}

            <div className="pt-4 border-t">
              <div className="flex items-center justify-between mb-3">
                <div>
                  <h3 className="font-semibold">Complementary Items</h3>
                  <p className="text-xs text-muted-foreground">Document items not listed above</p>
                </div>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => addComplementaryItem(currentArea.key)}
                  data-testid="button-add-complementary"
                >
                  <Plus className="h-4 w-4 mr-1.5" />
                  Add Item
                </Button>
              </div>

              <div className="space-y-3">
                {currentAreaData.complementary.map(item => (
                  <ComplementaryItemCard key={item.id} item={item} />
                ))}
                {currentAreaData.complementary.length === 0 && (
                  <p className="text-sm text-muted-foreground text-center py-4">
                    No complementary items added
                  </p>
                )}
              </div>
            </div>
          </div>
        </main>

        <div className="lg:hidden fixed bottom-0 left-0 right-0 p-4 bg-background border-t">
          <div className="flex gap-3">
            <Button
              variant="outline"
              className="flex-1"
              disabled={currentAreaIndex === 0}
              onClick={() => handleNavigateToArea(currentAreaIndex - 1)}
            >
              <ArrowLeft className="h-4 w-4 mr-2" />
              Previous
            </Button>
            {currentAreaIndex < areas.length - 1 ? (
              <Button
                className="flex-1"
                onClick={() => handleNavigateToArea(currentAreaIndex + 1)}
              >
                Next
                <ArrowRight className="ml-2 h-4 w-4" />
              </Button>
            ) : (
              <Button
                className="flex-1"
                variant={allAreasComplete ? "default" : "outline"}
                onClick={handleSubmit}
                disabled={isSubmitting}
                data-testid="button-submit"
              >
                {isSubmitting ? (
                  <>
                    <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                    Submitting...
                  </>
                ) : (
                  "Submit"
                )}
              </Button>
            )}
          </div>
        </div>
      </div>

      <AlertDialog open={showExitDialog} onOpenChange={setShowExitDialog}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Exit Inspection?</AlertDialogTitle>
            <AlertDialogDescription>
              Your progress will be saved. You can continue later.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction onClick={() => setLocation("/home")}>
              Exit
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      <AlertDialog open={showValidationDialog} onOpenChange={setShowValidationDialog}>
        <AlertDialogContent className="max-h-[80vh] overflow-y-auto">
          <AlertDialogHeader>
            <AlertDialogTitle className="text-destructive">Incomplete Inspection</AlertDialogTitle>
            <AlertDialogDescription asChild>
              <div className="space-y-3">
                <p>Please complete the following items before submitting:</p>
                <div className="max-h-60 overflow-y-auto space-y-2">
                  {validationErrors.slice(0, 10).map((error, idx) => (
                    <div key={idx} className="flex items-center gap-2 text-sm">
                      <span className="text-destructive font-medium">{error.areaName}:</span>
                      <span>{error.itemName} - condition not set</span>
                    </div>
                  ))}
                  {validationErrors.length > 10 && (
                    <p className="text-sm text-muted-foreground">
                      ... and {validationErrors.length - 10} more items
                    </p>
                  )}
                </div>
              </div>
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogAction onClick={() => setShowValidationDialog(false)}>
              Go Back & Complete
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      {editingImage && (
        <ImageEditor
          imageUrl={editingImage.url}
          onSave={handleSaveEditedImage}
          onCancel={() => setEditingImage(null)}
        />
      )}
    </div>
  );
}

