import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "@/components/ui/dialog";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { useToast } from "@/hooks/use-toast";
import { Plus, Pencil, Trash2, Building2, Search, Loader2 } from "lucide-react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { queryClient, apiRequest } from "@/lib/queryClient";
import type { Unit } from "@shared/schema";

export default function UnitsPage() {
  const { toast } = useToast();
  const [search, setSearch] = useState("");
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [editingUnit, setEditingUnit] = useState<Unit | null>(null);
  const [formData, setFormData] = useState({
    propertyName: "",
    unitNumber: "",
    address: "",
    notes: "",
  });

  const { data: units, isLoading } = useQuery<Unit[]>({
    queryKey: ["/api/units"],
  });

  const createMutation = useMutation({
    mutationFn: async (data: typeof formData) => {
      return apiRequest("POST", "/api/units", data);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/units"] });
      toast({ title: "Unit Created", description: "The unit has been added successfully." });
      handleCloseDialog();
    },
    onError: (error) => {
      toast({ variant: "destructive", title: "Error", description: error.message });
    },
  });

  const updateMutation = useMutation({
    mutationFn: async ({ id, data }: { id: string; data: typeof formData }) => {
      return apiRequest("PATCH", `/api/units/${id}`, data);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/units"] });
      toast({ title: "Unit Updated", description: "The unit has been updated successfully." });
      handleCloseDialog();
    },
    onError: (error) => {
      toast({ variant: "destructive", title: "Error", description: error.message });
    },
  });

  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      return apiRequest("DELETE", `/api/units/${id}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/units"] });
      toast({ title: "Unit Deleted", description: "The unit has been removed." });
    },
    onError: (error) => {
      toast({ variant: "destructive", title: "Error", description: error.message });
    },
  });

  const filteredUnits = units?.filter(
    (unit) =>
      unit.propertyName.toLowerCase().includes(search.toLowerCase()) ||
      unit.unitNumber.toLowerCase().includes(search.toLowerCase()) ||
      unit.address.toLowerCase().includes(search.toLowerCase())
  );

  const handleOpenDialog = (unit?: Unit) => {
    if (unit) {
      setEditingUnit(unit);
      setFormData({
        propertyName: unit.propertyName,
        unitNumber: unit.unitNumber,
        address: unit.address,
        notes: unit.notes || "",
      });
    } else {
      setEditingUnit(null);
      setFormData({ propertyName: "", unitNumber: "", address: "", notes: "" });
    }
    setIsDialogOpen(true);
  };

  const handleCloseDialog = () => {
    setIsDialogOpen(false);
    setEditingUnit(null);
    setFormData({ propertyName: "", unitNumber: "", address: "", notes: "" });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingUnit) {
      updateMutation.mutate({ id: editingUnit.id, data: formData });
    } else {
      createMutation.mutate(formData);
    }
  };

  const isPending = createMutation.isPending || updateMutation.isPending;

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold">Units</h1>
          <p className="text-muted-foreground">Manage property units</p>
        </div>
        <Button onClick={() => handleOpenDialog()} data-testid="button-add-unit">
          <Plus className="mr-2 h-4 w-4" />
          Add Unit
        </Button>
      </div>

      <Card>
        <CardHeader className="pb-4">
          <div className="flex items-center gap-2">
            <Search className="h-4 w-4 text-muted-foreground" />
            <Input
              placeholder="Search units..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="max-w-sm"
              data-testid="input-search"
            />
          </div>
        </CardHeader>
        <CardContent>
          {isLoading ? (
            <div className="flex items-center justify-center py-8">
              <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
            </div>
          ) : filteredUnits?.length === 0 ? (
            <div className="text-center py-8">
              <Building2 className="h-12 w-12 mx-auto text-muted-foreground/50 mb-4" />
              <p className="text-muted-foreground">No units found</p>
            </div>
          ) : (
            <div className="rounded-md border">
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Property</TableHead>
                    <TableHead>Unit</TableHead>
                    <TableHead className="hidden md:table-cell">Address</TableHead>
                    <TableHead>Status</TableHead>
                    <TableHead className="text-right">Actions</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {filteredUnits?.map((unit) => (
                    <TableRow key={unit.id} data-testid={`unit-row-${unit.id}`}>
                      <TableCell className="font-medium">{unit.propertyName}</TableCell>
                      <TableCell>{unit.unitNumber}</TableCell>
                      <TableCell className="hidden md:table-cell">{unit.address}</TableCell>
                      <TableCell>
                        <Badge variant={unit.isActive ? "default" : "secondary"}>
                          {unit.isActive ? "Active" : "Inactive"}
                        </Badge>
                      </TableCell>
                      <TableCell className="text-right">
                        <div className="flex justify-end gap-2">
                          <Button
                            variant="ghost"
                            size="icon"
                            onClick={() => handleOpenDialog(unit)}
                            data-testid={`button-edit-${unit.id}`}
                          >
                            <Pencil className="h-4 w-4" />
                          </Button>
                          <Button
                            variant="ghost"
                            size="icon"
                            onClick={() => deleteMutation.mutate(unit.id)}
                            disabled={deleteMutation.isPending}
                            data-testid={`button-delete-${unit.id}`}
                          >
                            <Trash2 className="h-4 w-4 text-destructive" />
                          </Button>
                        </div>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </div>
          )}
        </CardContent>
      </Card>

      <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle>{editingUnit ? "Edit Unit" : "Add Unit"}</DialogTitle>
          </DialogHeader>
          <form onSubmit={handleSubmit} className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="propertyName">Property Name *</Label>
              <Input
                id="propertyName"
                value={formData.propertyName}
                onChange={(e) => setFormData({ ...formData, propertyName: e.target.value })}
                required
                data-testid="input-property-name"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="unitNumber">Unit Number *</Label>
              <Input
                id="unitNumber"
                value={formData.unitNumber}
                onChange={(e) => setFormData({ ...formData, unitNumber: e.target.value })}
                required
                data-testid="input-unit-number"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="address">Address *</Label>
              <Input
                id="address"
                value={formData.address}
                onChange={(e) => setFormData({ ...formData, address: e.target.value })}
                required
                data-testid="input-address"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="notes">Notes</Label>
              <Textarea
                id="notes"
                value={formData.notes}
                onChange={(e) => setFormData({ ...formData, notes: e.target.value })}
                data-testid="input-notes"
              />
            </div>
            <DialogFooter>
              <Button type="button" variant="outline" onClick={handleCloseDialog}>
                Cancel
              </Button>
              <Button type="submit" disabled={isPending} data-testid="button-save">
                {isPending ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : null}
                {editingUnit ? "Update" : "Create"}
              </Button>
            </DialogFooter>
          </form>
        </DialogContent>
      </Dialog>
    </div>
  );
}

client/src/components/portal/sidebar.tsx.content:
import { useState, useEffect } from "react";
import { Link, useLocation } from "wouter";
import { Avatar, AvatarFallback } from "@/components/ui/avatar";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Tooltip, TooltipContent, TooltipTrigger } from "@/components/ui/tooltip";
import {
  LayoutDashboard,
  Building2,
  Users,
  ClipboardCheck,
  AlertTriangle,
  Image,
  BarChart3,
  Settings,
  ShieldCheck,
  ChevronDown,
  ChevronRight,
  FileSearch,
  ClipboardList,
  PanelLeftClose,
  PanelLeftOpen,
  X,
  FileText,
} from "lucide-react";
import type { User } from "@shared/schema";

interface SidebarProps {
  user: User | null;
  collapsed: boolean;
  onToggleCollapse: () => void;
  mobileOpen?: boolean;
  onMobileClose?: () => void;
}

interface MenuItem {
  title: string;
  url?: string;
  icon: React.ComponentType<{ className?: string }>;
  children?: { title: string; url: string }[];
}

const menuItems: MenuItem[] = [
  { title: "Dashboard", url: "/portal", icon: LayoutDashboard },
  { title: "Units", url: "/portal/units", icon: Building2 },
  { title: "Users", url: "/portal/users", icon: Users },
  { title: "Tasks", url: "/portal/tasks", icon: ClipboardCheck },
  { 
    title: "Inspections", 
    icon: FileSearch,
    children: [
      { title: "Full Inspection", url: "/portal/inspections/full" },
      { title: "Onboarding", url: "/portal/inspections/onboarding" },
    ]
  },
  { title: "Form Templates", url: "/portal/form-template", icon: ClipboardList },
  { title: "Quick Reports", url: "/portal/quick-reports", icon: AlertTriangle },
  { title: "Media Library", url: "/portal/media", icon: Image },
  { title: "Reports", url: "/portal/reports", icon: BarChart3 },
  { title: "Settings", url: "/portal/settings", icon: Settings },
];

const adminMenuItems = [
  { title: "Admin Dashboard", url: "/admin/dashboard", icon: ShieldCheck },
  { title: "Admin Users", url: "/admin/users", icon: Users },
];

export function PortalSidebar({ user, collapsed, onToggleCollapse, mobileOpen, onMobileClose }: SidebarProps) {
  const [location] = useLocation();
  const [expandedMenus, setExpandedMenus] = useState<Record<string, boolean>>({
    Inspections: location.startsWith("/portal/inspections"),
  });

  useEffect(() => {
    if (mobileOpen && onMobileClose) {
      onMobileClose();
    }
  }, [location]);

  const toggleMenu = (title: string) => {
    if (collapsed && !mobileOpen) return;
    setExpandedMenus(prev => ({ ...prev, [title]: !prev[title] }));
  };

  const handleNavClick = () => {
    if (mobileOpen && onMobileClose) {
      onMobileClose();
    }
  };

  const showLabels = !collapsed || mobileOpen;

  const renderSidebarInner = (isMobile: boolean) => {
    const sidebarWidth = isMobile ? "w-[280px]" : collapsed ? "w-[72px]" : "w-[260px]";
    const mobileTranslate = isMobile
      ? (mobileOpen ? "translate-x-0" : "-translate-x-full")
      : "";

    return (
      <aside
        className={`fixed left-0 top-0 bottom-0 flex flex-col z-50 transition-all duration-300 ${sidebarWidth} ${mobileTranslate}`}
        style={{
          background: "linear-gradient(180deg, #4c1d95 0%, #5b21b6 50%, #6d28d9 100%)",
        }}
        data-testid="portal-sidebar"
      >
        <div className={`py-5 flex items-center justify-between ${!showLabels ? "px-4" : "px-6"}`}>
          <Link href="/portal" onClick={handleNavClick}>
            <div className={`flex items-center cursor-pointer ${!showLabels ? "justify-center" : "gap-3"}`}>
              <div className="h-10 w-10 rounded-xl bg-white/20 flex items-center justify-center flex-shrink-0">
                <ClipboardCheck className="h-5 w-5 text-white" />
              </div>
              {showLabels && <span className="font-bold text-lg text-white tracking-tight">TBA Portal</span>}
            </div>
          </Link>
          {isMobile && onMobileClose && (
            <Button
              variant="ghost"
              size="icon"
              onClick={onMobileClose}
              className="h-8 w-8 bg-white/10 text-white"
              data-testid="button-close-mobile-sidebar"
            >
              <X className="h-4 w-4" />
            </Button>
          )}
        </div>

        {!isMobile && (
          <div className={`px-3 mb-2 ${collapsed ? "flex justify-center" : ""}`}>
            <Button
              variant="ghost"
              size="icon"
              onClick={onToggleCollapse}
              className="h-8 w-8 bg-white/10 hover:bg-white/20 text-white"
              data-testid="button-toggle-sidebar"
            >
              {collapsed ? (
                <PanelLeftOpen className="h-4 w-4" />
              ) : (
                <PanelLeftClose className="h-4 w-4" />
              )}
            </Button>
          </div>
        )}

        <nav className="flex-1 px-3 py-4 space-y-1 overflow-y-auto">
          {user?.role === "ADMIN" && adminMenuItems.map((item) => {
            const isActive = location === item.url || location.startsWith(item.url);

            const menuContent = (
              <Link key={item.title} href={item.url} onClick={handleNavClick}>
                <div
                  className={`flex items-center px-3 py-2.5 rounded-xl cursor-pointer transition-all ${
                    !showLabels ? "justify-center" : "gap-3"
                  } ${isActive ? "bg-white/20" : "hover:bg-white/10"}`}
                  data-testid={`nav-${item.title.toLowerCase().replace(/\s+/g, "-")}`}
                >
                  <div className={`h-9 w-9 rounded-lg flex items-center justify-center flex-shrink-0 ${
                    isActive ? "bg-white/20" : "bg-white/10"
                  }`}>
                    <item.icon className="h-5 w-5 text-white" />
                  </div>
                  {showLabels && (
                    <span className={`font-medium text-sm ${
                      isActive ? "text-white" : "text-white/80"
                    }`}>
                      {item.title}
                    </span>
                  )}
                </div>
              </Link>
            );

            if (!showLabels) {
              return (
                <Tooltip key={item.title} delayDuration={0}>
                  <TooltipTrigger asChild>{menuContent}</TooltipTrigger>
                  <TooltipContent side="right" className="bg-violet-900 text-white border-violet-800">
                    {item.title}
                  </TooltipContent>
                </Tooltip>
              );
            }

            return menuContent;
          })}

          {user?.role === "ADMIN" && (
            <div className="border-t border-white/10 my-2" />
          )}

          {menuItems.map((item) => {
            const hasChildren = item.children && item.children.length > 0;
            const isExpanded = expandedMenus[item.title] && showLabels;
            const isActive = item.url 
              ? (location === item.url || (item.url !== "/portal" && location.startsWith(item.url)))
              : item.children?.some(child => location === child.url || location.startsWith(child.url));

            if (hasChildren) {
              const menuWithChildrenContent = (
                <div
                  onClick={() => toggleMenu(item.title)}
                  className={`flex items-center px-3 py-2.5 rounded-xl cursor-pointer transition-all ${
                    !showLabels ? "justify-center" : "gap-3"
                  } ${isActive ? "bg-white/20" : "hover:bg-white/10"}`}
                  data-testid={`nav-${item.title.toLowerCase().replace(/\s+/g, "-")}`}
                >
                  <div className={`h-9 w-9 rounded-lg flex items-center justify-center flex-shrink-0 ${
                    isActive ? "bg-white/20" : "bg-white/10"
                  }`}>
                    <item.icon className="h-5 w-5 text-white" />
                  </div>
                  {showLabels && (
                    <>
                      <span className={`font-medium text-sm flex-1 ${
                        isActive ? "text-white" : "text-white/80"
                      }`}>
                        {item.title}
                      </span>
                      {isExpanded ? (
                        <ChevronDown className="h-4 w-4 text-white/70" />
                      ) : (
                        <ChevronRight className="h-4 w-4 text-white/70" />
                      )}
                    </>
                  )}
                </div>
              );

              if (!showLabels) {
                return (
                  <Tooltip key={item.title} delayDuration={0}>
                    <TooltipTrigger asChild>
                      <div>{menuWithChildrenContent}</div>
                    </TooltipTrigger>
                    <TooltipContent side="right" className="bg-violet-900 text-white border-violet-800">
                      <div className="space-y-1">
                        <p className="font-medium">{item.title}</p>
                        {item.children?.map((child) => (
                          <Link key={child.title} href={child.url} onClick={handleNavClick}>
                            <p className="text-xs text-white/80 hover:text-white cursor-pointer py-0.5">
                              {child.title}
                            </p>
                          </Link>
                        ))}
                      </div>
                    </TooltipContent>
                  </Tooltip>
                );
              }

              return (
                <div key={item.title}>
                  {menuWithChildrenContent}
                  {isExpanded && (
                    <div className="ml-12 mt-1 space-y-1">
                      {item.children?.map((child) => {
                        const isChildActive = location === child.url || location.startsWith(child.url);
                        return (
                          <Link key={child.title} href={child.url} onClick={handleNavClick}>
                            <div
                              className={`px-3 py-2 rounded-lg cursor-pointer transition-all ${
                                isChildActive
                                  ? "bg-white/20 text-white"
                                  : "text-white/70 hover:bg-white/10 hover:text-white"
                              }`}
                              data-testid={`nav-${child.title.toLowerCase().replace(/\s+/g, "-")}`}
                            >
                              <span className="text-sm font-medium">{child.title}</span>
                            </div>
                          </Link>
                        );
                      })}
                    </div>
                  )}
                </div>
              );
            }

            const regularMenuContent = (
              <Link key={item.title} href={item.url!} onClick={handleNavClick}>
                <div
                  className={`flex items-center px-3 py-2.5 rounded-xl cursor-pointer transition-all ${
                    !showLabels ? "justify-center" : "gap-3"
                  } ${isActive ? "bg-white/20" : "hover:bg-white/10"}`}
                  data-testid={`nav-${item.title.toLowerCase().replace(/\s+/g, "-")}`}
                >
                  <div className={`h-9 w-9 rounded-lg flex items-center justify-center flex-shrink-0 ${
                    isActive ? "bg-white/20" : "bg-white/10"
                  }`}>
                    <item.icon className="h-5 w-5 text-white" />
                  </div>
                  {showLabels && (
                    <span className={`font-medium text-sm ${
                      isActive ? "text-white" : "text-white/80"
                    }`}>
                      {item.title}
                    </span>
                  )}
                </div>
              </Link>
            );

            if (!showLabels) {
              return (
                <Tooltip key={item.title} delayDuration={0}>
                  <TooltipTrigger asChild>{regularMenuContent}</TooltipTrigger>
                  <TooltipContent side="right" className="bg-violet-900 text-white border-violet-800">
                    {item.title}
                  </TooltipContent>
                </Tooltip>
              );
            }

            return regularMenuContent;
          })}
        </nav>

        <div className={`py-4 border-t border-white/10 ${!showLabels ? "px-2" : "px-4"}`}>
          <div className={`flex items-center ${!showLabels ? "justify-center" : "gap-3 px-2"}`}>
            <Tooltip delayDuration={0}>
              <TooltipTrigger asChild>
                <Avatar className="h-10 w-10 border-2 border-white/20 flex-shrink-0 cursor-pointer">
                  <AvatarFallback className="bg-white/20 text-white font-semibold">
                    {user?.name?.charAt(0).toUpperCase() || "U"}
                  </AvatarFallback>
                </Avatar>
              </TooltipTrigger>
              {!showLabels && (
                <TooltipContent side="right" className="bg-violet-900 text-white border-violet-800">
                  <p className="font-medium">{user?.name || "User"}</p>
                  <p className="text-xs text-white/80">{user?.role || "USER"}</p>
                </TooltipContent>
              )}
            </Tooltip>
            {showLabels && (
              <div className="flex-1 min-w-0">
                <p className="text-sm font-medium text-white truncate">{user?.name || "User"}</p>
                <Badge 
                  className="bg-white/20 text-white/90 hover:bg-white/25 text-[10px] px-2 py-0 border-0 font-normal"
                >
                  {user?.role || "USER"}
                </Badge>
              </div>
            )}
          </div>
        </div>
      </aside>
    );
  };

  return (
    <>
      {/* Desktop sidebar - always visible */}
      <div className="hidden md:block">
        {renderSidebarInner(false)}
      </div>

      {/* Mobile sidebar - off-canvas with backdrop */}
      <div className="md:hidden">
        {mobileOpen && (
          <div
            className="fixed inset-0 bg-black/50 z-40"
            onClick={onMobileClose}
            data-testid="mobile-sidebar-backdrop"
          />
        )}
        {renderSidebarInner(true)}
      </div>
    </>
  );
}

