export default function FullInspectionPage() {
  const { user } = useAuth();
  const [, setLocation] = useLocation();
  const { toast } = useToast();

  const [step, setStep] = useState<"setup" | "inspection" | "complete">("setup");
  const [unitId, setUnitId] = useState("");
  const [pmId, setPmId] = useState("");
  const [currentRoomIndex, setCurrentRoomIndex] = useState(0);
  const [responses, setResponses] = useState<AllResponses>({});
  const [showExitDialog, setShowExitDialog] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const { data: units } = useQuery<Unit[]>({ queryKey: ["/api/units"] });
  const { data: pms } = useQuery<User[]>({ queryKey: ["/api/users/pms"] });
  const { data: template } = useQuery<InspectionTemplate>({ queryKey: ["/api/templates/full-inspection"] });

  const rooms: TemplateRoom[] = template?.rooms || DEFAULT_TEMPLATE;
  const currentRoom = rooms[currentRoomIndex];

  useEffect(() => {
    const saved = localStorage.getItem("fullInspectionDraft");
    if (saved) {
      try {
        const data = JSON.parse(saved);
        if (data.responses) {
          // Convert timestamp strings back to Date objects in media
          const restoredResponses: AllResponses = {};
          for (const roomKey in data.responses) {
            restoredResponses[roomKey] = {};
            for (const itemKey in data.responses[roomKey]) {
              const item = data.responses[roomKey][itemKey];
              restoredResponses[roomKey][itemKey] = {
                ...item,
                media: item.media?.map((m: MediaPreview & { timestamp: string | Date }) => ({
                  ...m,
                  timestamp: typeof m.timestamp === 'string' ? new Date(m.timestamp) : m.timestamp,
                })),
              };
            }
          }
          setResponses(restoredResponses);
        }
        if (data.unitId) setUnitId(data.unitId);
        if (data.pmId) setPmId(data.pmId);
        if (data.step) setStep(data.step);
        if (typeof data.currentRoomIndex === "number") setCurrentRoomIndex(data.currentRoomIndex);
      } catch (e) {
        console.error("Failed to restore draft:", e);
      }
    }
  }, []);

  useEffect(() => {
    if (step === "inspection" || responses && Object.keys(responses).length > 0) {
      localStorage.setItem("fullInspectionDraft", JSON.stringify({
        responses,
        unitId,
        pmId,
        step,
        currentRoomIndex,
      }));
    }
  }, [responses, unitId, pmId, step, currentRoomIndex]);

  const updateItemResponse = (roomKey: string, itemKey: string, data: Partial<ItemResponse>) => {
    setResponses((prev) => ({
      ...prev,
      [roomKey]: {
        ...prev[roomKey],
        [itemKey]: {
          ...prev[roomKey]?.[itemKey],
          ...data,
        },
      },
    }));
  };

  const isRoomComplete = (room: TemplateRoom): boolean => {
    const roomResponses = responses[room.key] || {};
    return room.items.every((item) => {
      if (!item.required) return true;
      const response = roomResponses[item.key];
      if (!response?.result) return false;
      // N/A items don't require media
      if (item.requiresMedia && response.result !== "NA" && (!response.media || response.media.length === 0)) return false;
      return true;
    });
  };

  const getRoomProgress = (): number => {
    let completed = 0;
    rooms.forEach((room) => {
      if (isRoomComplete(room)) completed++;
    });
    return (completed / rooms.length) * 100;
  };

  const handleStartInspection = () => {
    if (!unitId) {
      toast({ variant: "destructive", title: "Unit Required" });
      return;
    }
    if (!pmId) {
      toast({ variant: "destructive", title: "PM Required" });
      return;
    }
    setStep("inspection");
  };

  const handleNextRoom = () => {
    if (!isRoomComplete(currentRoom)) {
      toast({ 
        variant: "destructive", 
        title: "Complete All Items", 
        description: "Please complete all required items with photos before proceeding." 
      });
      return;
    }
    if (currentRoomIndex < rooms.length - 1) {
      setCurrentRoomIndex(currentRoomIndex + 1);
      window.scrollTo(0, 0);
    }
  };

  const handlePrevRoom = () => {
    if (currentRoomIndex > 0) {
      setCurrentRoomIndex(currentRoomIndex - 1);
      window.scrollTo(0, 0);
    }
  };

  const canSubmit = rooms.every((room) => isRoomComplete(room));

  const submitMutation = useMutation({
    mutationFn: async () => {
      const formData = new FormData();
      formData.append("unitId", unitId);
      formData.append("responsiblePmId", pmId);
      formData.append("createdById", user?.id || "");
      formData.append("type", "FULL_INSPECTION");

      const checklistData: Array<{
        roomKey: string;
        itemKey: string;
        result: ChecklistResult;
        notes?: string;
        severity?: Severity;
        mediaIndices: number[];
      }> = [];

      let mediaIndex = 0;
      rooms.forEach((room) => {
        const roomResponses = responses[room.key] || {};
        room.items.forEach((item) => {
          const response = roomResponses[item.key];
          if (response?.result) {
            const mediaIndices: number[] = [];
            if (response.media) {
              response.media.forEach((m) => {
                formData.append(`media_${mediaIndex}`, m.file);
                formData.append(`mediaType_${mediaIndex}`, m.type);
                formData.append(`mediaTimestamp_${mediaIndex}`, m.timestamp.toISOString());
                mediaIndices.push(mediaIndex);
                mediaIndex++;
              });
            }
            checklistData.push({
              roomKey: room.key,
              itemKey: item.key,
              result: response.result,
              notes: response.notes,
              severity: response.severity,
              mediaIndices,
            });
          }
        });
      });

      formData.append("checklistData", JSON.stringify(checklistData));
      formData.append("mediaCount", mediaIndex.toString());

      const res = await fetch("/api/inspections/full", {
        method: "POST",
        body: formData,
        credentials: "include",
      });
      if (!res.ok) {
        const error = await res.json();
        throw new Error(error.message || "Submission failed");
      }
      return res.json();
    },
    onSuccess: () => {
      localStorage.removeItem("fullInspectionDraft");
      queryClient.invalidateQueries({ queryKey: ["/api/inspection-tasks"] });
      setStep("complete");
    },
    onError: (error) => {
      toast({
        variant: "destructive",
        title: "Submission Failed",
        description: error instanceof Error ? error.message : "Could not submit inspection",
      });
    },
  });

  const handleSubmit = async () => {
    if (!canSubmit) {
      toast({ variant: "destructive", title: "Incomplete", description: "Complete all rooms first" });
      return;
    }
    setIsSubmitting(true);
    try {
      await submitMutation.mutateAsync();
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleExit = () => {
    if (Object.keys(responses).length > 0) {
      setShowExitDialog(true);
    } else {
      setLocation("/home");
    }
  };

  if (step === "complete") {
    return (
      <div className="min-h-screen bg-background flex flex-col items-center justify-center p-4">
        <div className="text-center space-y-4">
          <div className="mx-auto w-20 h-20 rounded-full bg-chart-2/20 flex items-center justify-center">
            <CheckCircle2 className="h-10 w-10 text-chart-2" />
          </div>
          <h1 className="text-2xl font-bold">Inspection Submitted!</h1>
          <p className="text-muted-foreground">Your full inspection has been submitted successfully.</p>
          <Button onClick={() => setLocation("/home")} data-testid="button-done">
            Return Home
          </Button>
        </div>
      </div>
    );
  }

  if (step === "setup") {
    return (
      <div className="min-h-screen bg-background flex flex-col">
        <header className="sticky top-0 z-50 flex items-center gap-4 p-4 border-b bg-background/95 backdrop-blur">
          <Button variant="ghost" size="icon" onClick={() => setLocation("/home")} data-testid="button-back">
            <ArrowLeft className="h-5 w-5" />
          </Button>
          <div className="flex-1">
            <h1 className="font-semibold text-lg">Full Inspection</h1>
            <p className="text-xs text-muted-foreground">Setup</p>
          </div>
          <ThemeToggle />
        </header>

        <main className="flex-1 p-4 space-y-6">
          <Card>
            <CardHeader>
              <CardTitle>Select Unit & PM</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="space-y-2">
                <Label>Unit <span className="text-destructive">*</span></Label>
                <Select value={unitId} onValueChange={setUnitId}>
                  <SelectTrigger data-testid="select-unit">
                    <SelectValue placeholder="Select unit" />
                  </SelectTrigger>
                  <SelectContent>
                    {units?.map((unit) => (
                      <SelectItem key={unit.id} value={unit.id}>
                        {unit.propertyName} - {unit.unitNumber}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-2">
                <Label>Responsible PM <span className="text-destructive">*</span></Label>
                <Select value={pmId} onValueChange={setPmId}>
                  <SelectTrigger data-testid="select-pm">
                    <SelectValue placeholder="Select PM" />
                  </SelectTrigger>
                  <SelectContent>
                    {pms?.map((pm) => (
                      <SelectItem key={pm.id} value={pm.id}>
                        {pm.name}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle>Rooms to Inspect</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="space-y-2">
                {rooms.map((room, i) => (
                  <div key={room.key} className="flex items-center justify-between py-2 border-b last:border-0">
                    <span className="font-medium">{i + 1}. {room.name}</span>
                    <span className="text-sm text-muted-foreground">{room.items.length} items</span>
                  </div>
                ))}
              </div>
            </CardContent>
          </Card>

          <Button
            className="w-full"
            size="lg"
            onClick={handleStartInspection}
            disabled={!unitId || !pmId}
            data-testid="button-start"
          >
            Start Inspection
            <ArrowRight className="ml-2 h-4 w-4" />
          </Button>
        </main>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background flex flex-col">
      <header className="sticky top-0 z-50 flex flex-col gap-2 p-4 border-b bg-background/95 backdrop-blur">
        <div className="flex items-center gap-4">
          <Button variant="ghost" size="icon" onClick={handleExit} data-testid="button-exit">
            <ChevronLeft className="h-5 w-5" />
          </Button>
          <div className="flex-1">
            <h1 className="font-semibold">{currentRoom.name}</h1>
            <p className="text-xs text-muted-foreground">
              Room {currentRoomIndex + 1} of {rooms.length}
            </p>
          </div>
          <ThemeToggle />
        </div>
        <Progress value={getRoomProgress()} className="h-2" />
      </header>

      <main className="flex-1 p-4 pb-24 space-y-4">
        {currentRoom.items.map((item) => {
          const response = responses[currentRoom.key]?.[item.key] || {};
          return (
            <ChecklistItem
              key={item.key}
              item={item}
              roomKey={currentRoom.key}
              value={response.result}
              notes={response.notes}
              severity={response.severity}
              media={response.media}
              onChange={(data) => updateItemResponse(currentRoom.key, item.key, data)}
              inspectionType="FULL_INSPECTION"
            />
          );
        })}
      </main>

      <div className="fixed bottom-0 left-0 right-0 z-50 p-4 border-t bg-background/95 backdrop-blur flex gap-2">
        {currentRoomIndex > 0 && (
          <Button variant="outline" onClick={handlePrevRoom} data-testid="button-prev">
            <ArrowLeft className="mr-2 h-4 w-4" />
            Previous
          </Button>
        )}

        {currentRoomIndex < rooms.length - 1 ? (
          <Button
            className="flex-1"
            onClick={handleNextRoom}
            disabled={!isRoomComplete(currentRoom)}
            data-testid="button-next"
          >
            Next Room
            <ArrowRight className="ml-2 h-4 w-4" />
          </Button>
        ) : (
          <Button
            className="flex-1"
            onClick={handleSubmit}
            disabled={!canSubmit || isSubmitting}
            data-testid="button-submit"
          >
            {isSubmitting ? (
              <>
                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                Submitting...
              </>
            ) : (
              <>
                <Upload className="mr-2 h-4 w-4" />
                Submit Inspection
              </>
            )}
          </Button>
        )}
      </div>

      <AlertDialog open={showExitDialog} onOpenChange={setShowExitDialog}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Leave Inspection?</AlertDialogTitle>
            <AlertDialogDescription>
              Your progress will be saved and you can resume later.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Continue Inspection</AlertDialogCancel>
            <AlertDialogAction onClick={() => setLocation("/home")}>
              Save & Exit
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

