      mkItem("Armchairs", buildItemBlocks({ hasCount: true, issues: ["Stains", "Wear and tear", "Wobbly legs", "Fabric damage"] })),
      mkItem("Side Tables", buildItemBlocks({ hasCount: true, issues: ["Scratches", "Water rings", "Wobbly"] })),
