import { useAuth } from "@/lib/auth";
import { useQuery } from "@tanstack/react-query";
import { SummaryCards, InspectionInboxTable } from "@/components/portal";
import type { InspectionTask, User, Unit } from "@shared/schema";

export default function DashboardPage() {
  const { user } = useAuth();

  const { data: tasks, isLoading: tasksLoading } = useQuery<InspectionTask[]>({
    queryKey: ["/api/inspection-tasks"],
  });

  const { data: users } = useQuery<User[]>({
    queryKey: ["/api/users"],
  });

  const { data: units } = useQuery<Unit[]>({
    queryKey: ["/api/units"],
  });

  // Summary stats (these would come from checklist responses in a real app)
  const stats = {
    good: 24,
    missing: 3,
    needReplacement: 5,
    issuesLogged: 8,
  };

  return (
    <div className="space-y-6">
      {/* Page Header */}
      <div>
        <h1 className="text-2xl font-bold text-gray-900" data-testid="text-dashboard-title">
          Dashboard
        </h1>
        <p className="text-gray-500 mt-1">Welcome back, {user?.name}</p>
      </div>

      {/* Summary Cards */}
      <SummaryCards
        good={stats.good}
        missing={stats.missing}
        needReplacement={stats.needReplacement}
        issuesLogged={stats.issuesLogged}
      />

      {/* Inspection Inbox Table */}
      <InspectionInboxTable
        tasks={tasks || []}
        users={users || []}
        units={units || []}
        isLoading={tasksLoading}
      />
    </div>
  );
}

