                <div className="w-full bg-muted rounded-full h-2">
                  <div
                    className={`h-2 rounded-full transition-all ${ownerRespondedCount === totalActionable && totalActionable > 0 ? "bg-green-500" : "bg-primary"}`}
                    style={{ width: `${totalActionable > 0 ? Math.round((ownerRespondedCount / totalActionable) * 100) : 0}%` }}
                  />
                </div>
              </div>
            </div>

            {(() => {
              const sectionOrder = ["Damage", "Cosmetic", "Missing", "Replacement", "Cleaning"];

              const groupedByCat: Record<string, OwnerReportItem[]> = {};
              for (const item of actionableItems) {
                const cat = categories.find((c) => c.id === item.categoryId);
                const catName = cat?.name || "Other";
                if (!groupedByCat[catName]) groupedByCat[catName] = [];
                groupedByCat[catName].push(item);
              }

              return (
                <>
                  {[...sectionOrder, ...Object.keys(groupedByCat).filter((k) => !sectionOrder.includes(k))].map((sectionName) => {
                    const sectionItems = groupedByCat[sectionName];
                    if (!sectionItems || sectionItems.length === 0) return null;
                    const cat = categories.find((c) => c.name === sectionName);

                    return (
                      <div key={sectionName} data-testid={`owner-response-section-${sectionName.toLowerCase()}`}>
                        <h3
                          className="text-sm font-bold uppercase tracking-wide pb-1.5 mb-3"
                          style={{ borderBottom: `2px solid ${cat?.color || "#6b7280"}`, color: cat?.color }}
                        >
                          {sectionName}
                        </h3>
                        <div className="space-y-2">
                          {sectionItems.map((item) => {
                            const responseInfo = item.ownerResponse ? OWNER_RESPONSE_LABELS[item.ownerResponse] : null;
                            return (
                              <div key={item.id} className="p-3 border rounded-lg" data-testid={`owner-response-item-${item.id}`}>
                                <div className="flex items-center justify-between gap-2 flex-wrap">
                                  <div className="flex-1 min-w-0">
                                    <span className="text-sm font-medium">{item.roomName} — {item.itemName}</span>
                                    {item.description && (
                                      <span className="text-xs text-muted-foreground ml-1">: {item.description}</span>
                                    )}
                                  </div>
                                  {responseInfo ? (
                                    <span className={`inline-flex items-center gap-1 text-xs px-2.5 py-1 rounded-full font-medium whitespace-nowrap ${responseInfo.color}`}>
                                      <CheckCircle2 className="w-3 h-3" />
                                      {responseInfo.label}
                                    </span>
                                  ) : (
                                    <span className="inline-flex items-center gap-1 text-xs px-2.5 py-1 rounded-full font-medium bg-muted text-muted-foreground whitespace-nowrap">
                                      <AlertTriangle className="w-3 h-3" />
                                      No response
                                    </span>
                                  )}
                                </div>
                                {item.ownerComment && (
                                  <div className="mt-2 bg-blue-50 dark:bg-blue-950/30 border border-blue-100 dark:border-blue-900 rounded-md px-3 py-2">
                                    <p className="text-xs text-blue-700 dark:text-blue-300">
                                      <MessageSquare className="w-3 h-3 inline mr-1" />
                                      {item.ownerComment}
                                    </p>
                                  </div>
                                )}
                              </div>
                            );
                          })}
                        </div>
                      </div>
                    );
                  })}
                </>
              );
            })()}
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

client/src/pages/mobile-home.tsx.content:
import { useLocation } from "wouter";
import { useAuth } from "@/lib/auth";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { ThemeToggle } from "@/components/theme-toggle";
import {
  ClipboardCheck,
  AlertTriangle,
  FileSearch,
  LogOut,
  Bell,
} from "lucide-react";

export default function MobileHomePage() {
  const { user, logout } = useAuth();
  const [, setLocation] = useLocation();

  const inspectionTypes = [];

  if (user?.role === "INSPECTOR" || user?.role === "PM" || user?.role === "ADMIN") {
    inspectionTypes.push({
      id: "onboarding",
      title: "Onboarding Inspection",
      description: "Full property condition documentation with room-by-room checklists",
      icon: ClipboardCheck,
      path: "/onboarding-inspection",
      color: "text-teal-600 dark:text-teal-400",
      bgColor: "bg-teal-50 dark:bg-teal-900/30",
    });
  }

  if (user?.role === "CLEANER" || user?.role === "INSPECTOR" || user?.role === "PM" || user?.role === "ADMIN") {
    inspectionTypes.push({
      id: "quick-report",
      title: "Quick Report",
      description: "Report damage or issues with photo/video evidence",
      icon: AlertTriangle,
      path: "/quick-report",
      color: "text-amber-600 dark:text-amber-400",
      bgColor: "bg-amber-50 dark:bg-amber-900/30",
    });
  }

  if (user?.role === "CLEANER" || user?.role === "PM" || user?.role === "ADMIN") {
    inspectionTypes.push({
      id: "full-inspection",
      title: "Full Inspection",
      description: "Complete room-by-room inspection checklist",
      icon: FileSearch,
      path: "/full-inspection",
      color: "text-blue-600 dark:text-blue-400",
      bgColor: "bg-blue-50 dark:bg-blue-900/30",
    });
  }

  return (
    <div className="min-h-screen bg-background flex flex-col">
      <header className="sticky top-0 z-50 flex items-center gap-4 p-4 border-b bg-background/95 backdrop-blur">
        <div className="flex-1">
          <h1 className="font-semibold text-lg" data-testid="text-welcome">
            Hi, {user?.name?.split(" ")[0] || "Inspector"}
          </h1>
          <p className="text-xs text-muted-foreground">
            {user?.role === "INSPECTOR" ? "Inspector" : user?.role === "CLEANER" ? "Cleaner" : user?.role}
          </p>
        </div>
        <Button
          variant="ghost"
          size="icon"
          onClick={() => setLocation("/notifications")}
          data-testid="button-notifications"
        >
          <Bell className="h-5 w-5" />
        </Button>
        <ThemeToggle />
        <Button variant="ghost" size="icon" onClick={() => logout()} data-testid="button-logout">
          <LogOut className="h-5 w-5" />
        </Button>
      </header>

      <main className="flex-1 p-4 space-y-4">
        <p className="text-sm text-muted-foreground">Select an inspection type to get started:</p>

        {inspectionTypes.map((type) => (
          <Card
            key={type.id}
            className="p-4 hover-elevate cursor-pointer"
            onClick={() => setLocation(type.path)}
            data-testid={`card-${type.id}`}
          >
            <div className="flex items-center gap-4">
              <div className={`w-12 h-12 rounded-lg ${type.bgColor} flex items-center justify-center flex-shrink-0`}>
                <type.icon className={`w-6 h-6 ${type.color}`} />
              </div>
              <div className="flex-1 min-w-0">
                <h2 className="font-semibold text-base">{type.title}</h2>
                <p className="text-xs text-muted-foreground mt-0.5">{type.description}</p>
              </div>
            </div>
          </Card>
        ))}
      </main>
    </div>
  );
}

client/src/pages/public-owner-report.tsx.content:
import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { useRoute } from "wouter";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import {
  AlertTriangle,
  CheckCircle2,
  ClipboardCheck,
  ExternalLink,
  Play,
  MessageSquare,
  Send,
  Check,
  X,
} from "lucide-react";
import { queryClient, apiRequest } from "@/lib/queryClient";
import type {
  OwnerReport,
  OwnerReportItem,
  IssueCategory,
  Unit,
  InspectionTask,
  OwnerResponseType,
} from "@shared/schema";

interface PublicReportData {
  report: OwnerReport;
  items: OwnerReportItem[];
  categories: IssueCategory[];
  unit: Unit | null;
  task: InspectionTask | null;
}

const RESPONSE_OPTIONS: {
  value: OwnerResponseType;
  label: string;
  color: string;
  bgColor: string;
  borderColor: string;
  missingOnly?: boolean;
}[] = [
  { value: "LEAVE_AS_IS", label: "Leave as is", color: "text-gray-700", bgColor: "bg-gray-100", borderColor: "border-gray-300" },
  { value: "ILL_REPLACE", label: "I'll replace", color: "text-blue-700", bgColor: "bg-blue-50", borderColor: "border-blue-300" },
  { value: "PLEASE_FIX", label: "Please fix", color: "text-amber-700", bgColor: "bg-amber-50", borderColor: "border-amber-300" },
  { value: "PROCEED_PURCHASE", label: "Please proceed with the purchase", color: "text-green-700", bgColor: "bg-green-50", borderColor: "border-green-300", missingOnly: true },
];

function getResponseLabel(value: string): string {
  return RESPONSE_OPTIONS.find(o => o.value === value)?.label || value;
}

function OwnerItemResponse({ item, token, isMissingOrReplacement }: {
  item: OwnerReportItem;
  token: string;
  isMissingOrReplacement: boolean;
}) {
  const [showComment, setShowComment] = useState(false);
  const [comment, setComment] = useState(item.ownerComment || "");
  const [selectedResponse, setSelectedResponse] = useState<string | null>(item.ownerResponse || null);
  const [saved, setSaved] = useState(!!item.ownerResponse || !!item.ownerComment);

  const respondMutation = useMutation({
    mutationFn: async ({ ownerResponse, ownerComment }: { ownerResponse?: string | null; ownerComment?: string | null }) => {
      const res = await apiRequest("POST", `/api/public/owner-report/${token}/items/${item.id}/respond`, {
        ownerResponse: ownerResponse || null,
        ownerComment: ownerComment !== undefined ? ownerComment : null,
      });
      return res.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/public/owner-report", token] });
      setSaved(true);
    },
  });

  const handleResponseClick = (response: string) => {
    setSelectedResponse(response);
    setSaved(false);
    respondMutation.mutate({ ownerResponse: response, ownerComment: comment || undefined });
  };

  const handleCommentSubmit = () => {
    if (comment.trim()) {
      respondMutation.mutate({ ownerResponse: selectedResponse, ownerComment: comment });
    }
  };

  const availableOptions = RESPONSE_OPTIONS.filter(
    opt => !opt.missingOnly || isMissingOrReplacement
  );

  return (
    <div className="mt-3 space-y-2">
      <div className="flex flex-wrap gap-2">
        {availableOptions.map((opt) => (
          <button
            key={opt.value}
            onClick={() => handleResponseClick(opt.value)}
            disabled={respondMutation.isPending}
            data-testid={`btn-response-${opt.value}-${item.id}`}
            className={`px-3 py-1.5 rounded-md text-xs font-medium border transition-all ${
              selectedResponse === opt.value
                ? `${opt.bgColor} ${opt.borderColor} ${opt.color} ring-2 ring-offset-1 ring-current`
                : `bg-white border-gray-200 text-gray-600 hover:bg-gray-50`
            }`}
          >
            {selectedResponse === opt.value && saved && (
              <Check className="w-3 h-3 inline mr-1" />
            )}
            {opt.label}
          </button>
        ))}
      </div>

      {!showComment && (
        <button
          onClick={() => setShowComment(true)}
          className="flex items-center gap-1 text-xs text-gray-400 hover:text-gray-600 transition-colors"
          data-testid={`btn-add-comment-${item.id}`}
        >
          <MessageSquare className="w-3 h-3" />
          {item.ownerComment ? "Edit comment" : "Add comment"}
        </button>
      )}

      {showComment && (
        <div className="flex gap-2 items-end">
          <Textarea
            value={comment}
            onChange={(e) => setComment(e.target.value)}
            placeholder="Add your comment..."
            className="text-sm min-h-[60px] flex-1"
            data-testid={`input-comment-${item.id}`}
          />
          <div className="flex flex-col gap-1">
            <Button
              size="icon"
              variant="default"
              onClick={handleCommentSubmit}
              disabled={respondMutation.isPending || !comment.trim()}
              data-testid={`btn-submit-comment-${item.id}`}
            >
              <Send className="w-4 h-4" />
            </Button>
            <Button
              size="icon"
              variant="ghost"
              onClick={() => setShowComment(false)}
              data-testid={`btn-cancel-comment-${item.id}`}
            >
              &times;
            </Button>
          </div>
        </div>
      )}

      {item.ownerComment && !showComment && (
        <div className="bg-blue-50 border border-blue-100 rounded-md px-3 py-2">
          <p className="text-xs text-blue-700" data-testid={`text-owner-comment-${item.id}`}>
            <MessageSquare className="w-3 h-3 inline mr-1" />
            {item.ownerComment}
          </p>
        </div>
      )}
    </div>
  );
}

function MediaLightbox({ url, onClose }: { url: string; onClose: () => void }) {
  const isVideo = url.match(/\.(mp4|mov|webm)$/i);
  return (
    <div
      className="fixed inset-0 z-[100] flex items-center justify-center bg-black/80"
      onClick={onClose}
      data-testid="media-lightbox"
    >
      <button
        onClick={onClose}
        className="absolute top-4 right-4 text-white bg-black/50 rounded-full p-2 z-10"
        data-testid="button-close-lightbox"
      >
        <X className="w-6 h-6" />
      </button>
      <div className="max-w-[90vw] max-h-[90vh]" onClick={(e) => e.stopPropagation()}>
        {isVideo ? (
          <video
            src={url}
            controls
            autoPlay
            className="max-w-full max-h-[85vh] rounded-lg"
            data-testid="lightbox-video"
          />
        ) : (
          <img
            src={url}
            alt="Evidence"
            className="max-w-full max-h-[85vh] object-contain rounded-lg"
            data-testid="lightbox-image"
          />
        )}
      </div>
    </div>
  );
}

function MediaThumbnails({ mediaUrls }: { mediaUrls: string[] }) {
  const [lightboxUrl, setLightboxUrl] = useState<string | null>(null);

  if (!mediaUrls || mediaUrls.length === 0) return null;
  return (
    <>
      <div className="flex gap-2 mt-2 flex-wrap">
        {mediaUrls.map((url, idx) => (
          <button
            key={idx}
            onClick={() => setLightboxUrl(url)}
            className="block w-16 h-16 rounded-lg overflow-hidden border cursor-pointer"
            data-testid={`btn-media-${idx}`}
          >
            {url.match(/\.(mp4|mov|webm)$/i) ? (
              <div className="w-full h-full bg-gray-100 flex items-center justify-center">
                <Play className="w-5 h-5 text-gray-400" />
              </div>
            ) : (
              <img src={url} alt="Evidence" className="w-full h-full object-cover" />
            )}
          </button>
        ))}
      </div>
      {lightboxUrl && (
        <MediaLightbox url={lightboxUrl} onClose={() => setLightboxUrl(null)} />
      )}
    </>
  );
}

function AmazonCartSection({ amazonCartLink }: { amazonCartLink: string }) {
  return (
    <div className="mt-4 p-3 bg-blue-50 rounded-lg">
      <p className="text-sm text-gray-700">
        Here is the Amazon cart link with the missing items compiled for your approval:
      </p>
      <a
        href={amazonCartLink}
        target="_blank"
        rel="noopener noreferrer"
        className="text-blue-600 text-sm underline flex items-center gap-1 mt-1"
        data-testid="link-amazon-cart"
      >
        <ExternalLink className="w-3 h-3" />
        View Amazon Cart
      </a>
    </div>
  );
}

export default function PublicOwnerReportPage() {
  const [, params] = useRoute("/report/:token");
  const token = params?.token;

  const { data, isLoading, error } = useQuery<PublicReportData>({
    queryKey: ["/api/public/owner-report", token],
    enabled: !!token,
  });

  if (isLoading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="animate-pulse space-y-4 w-full max-w-3xl mx-auto p-6">
          <div className="h-10 w-64 bg-gray-200 rounded mx-auto" />
          <div className="h-6 w-48 bg-gray-200 rounded mx-auto" />
          <div className="h-96 bg-gray-200 rounded" />
        </div>
      </div>
    );
  }

  if (error || !data) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <Card className="p-8 text-center max-w-md">
          <h2 className="text-xl font-semibold mb-2">Report Not Found</h2>
          <p className="text-gray-500">This report link may be invalid or has expired.</p>
        </Card>
      </div>
    );
  }

  const { report, items, categories, unit, task } = data;
  const categoryMap = new Map(categories.map((c) => [c.id, c]));

  const groupedByCategory: Record<string, OwnerReportItem[]> = {};
  for (const item of items) {
    const cat = categoryMap.get(item.categoryId);
    const catName = cat?.name || "Other";
    if (!groupedByCategory[catName]) groupedByCategory[catName] = [];
    groupedByCategory[catName].push(item);
  }

  const damageItems = groupedByCategory["Damage"] || [];
  const highPriority = damageItems.filter((i) => i.priority === "HIGH");
  const lowerPriority = damageItems.filter((i) => i.priority !== "HIGH");
  const missingItems = groupedByCategory["Missing"] || [];
  const replacementItems = groupedByCategory["Replacement"] || [];

  const ownerName = report.ownerName || "Owner";

  const respondedCount = items.filter(i => {
    const cat = categoryMap.get(i.categoryId);
    return cat?.name !== "Good" && i.ownerResponse;
  }).length;
  const totalActionableItems = items.filter(i => {
    const cat = categoryMap.get(i.categoryId);
    return cat?.name !== "Good";
  }).length;

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="bg-white border-b">
        <div className="max-w-3xl mx-auto px-6 py-6">
          <div className="flex items-center gap-3 justify-center mb-2">
            <div className="h-10 w-10 rounded-xl bg-violet-600 flex items-center justify-center">
              <ClipboardCheck className="h-5 w-5 text-white" />
            </div>
            <h1 className="text-xl font-bold text-gray-900" data-testid="text-report-header">
              Toronto Boutique Apartments
            </h1>
          </div>
          <p className="text-center text-gray-500 text-sm" data-testid="text-report-subtitle">
            Inspection Report for Property Owner
          </p>
          {totalActionableItems > 0 && (
            <div className="text-center mt-3">
              <Badge
                variant="outline"
                className={respondedCount === totalActionableItems ? "border-green-300 text-green-700" : "border-gray-300 text-gray-600"}
                data-testid="badge-response-progress"
              >
                {respondedCount === totalActionableItems ? (
                  <><Check className="w-3 h-3 mr-1" /> All items reviewed</>
                ) : (
                  <>{respondedCount} of {totalActionableItems} items reviewed</>
                )}
              </Badge>
            </div>
          )}
        </div>
      </div>

      <div className="max-w-3xl mx-auto px-6 py-8 space-y-8">
        <Card className="p-6 space-y-4 bg-white" data-testid="section-intro">
          <p className="text-base text-gray-900">
            Hi {ownerName},
          </p>
          <p className="text-sm text-gray-600">
            Following the inspection of your unit, we've identified both damages and missing items.
            Please review each item below and select your preferred action.
          </p>
          {unit && (
            <div className="flex gap-6 text-sm text-gray-500 mt-2 flex-wrap">
              <span>
                <span className="font-medium text-gray-700">Unit:</span>{" "}
                {unit.propertyName} - {unit.unitNumber}
              </span>
              {task && (
                <span>
                  <span className="font-medium text-gray-700">Inspection Date:</span>{" "}
                  {new Date(task.createdAt).toLocaleDateString()}
                </span>
              )}
            </div>
          )}
        </Card>

        {(highPriority.length > 0 || lowerPriority.length > 0) && (
          <Card className="p-6 bg-white" data-testid="section-damages">
            <h2 className="text-lg font-bold text-gray-900 border-b-2 border-red-500 pb-2 mb-4">
              Damages
            </h2>
            <p className="text-sm text-gray-600 mb-4">
              I'll start with the damages in order of priority:
            </p>

            {highPriority.length > 0 && (
              <div className="mb-6">
                <div className="flex items-center gap-2 mb-3">
                  <AlertTriangle className="w-4 h-4 text-red-500" />
                  <p className="font-semibold text-sm text-gray-900">
                    High priority (must be fixed before we go live):
                  </p>
                </div>
                <ul className="space-y-4">
                  {highPriority.map((item) => (
                    <li key={item.id} className="pl-6 border-l-2 border-red-200" data-testid={`public-damage-high-${item.id}`}>
                      <div className="flex-1">
                        <span className="font-medium text-gray-900">{item.roomName} — {item.itemName}</span>
                        {item.description && (
                          <span className="text-gray-600">: {item.description}</span>
                        )}
                        {item.repairQuote && (
                          <span className="text-gray-500"> — Repair quote: {item.repairQuote}</span>
                        )}
                        <MediaThumbnails mediaUrls={(item.mediaUrls as string[]) || []} />
                        <OwnerItemResponse item={item} token={token!} isMissingOrReplacement={false} />
                      </div>
                    </li>
                  ))}
                </ul>
              </div>
            )}

            {lowerPriority.length > 0 && (
              <div>
                <p className="font-semibold text-sm text-gray-900 mb-3">
                  Lower priority (cosmetic, not deal-breakers but recommended):
                </p>
                <ul className="space-y-4">
                  {lowerPriority.map((item) => (
                    <li key={item.id} className="pl-6 border-l-2 border-amber-200" data-testid={`public-damage-lower-${item.id}`}>
                      <div className="flex-1">
                        <span className="font-medium text-gray-900">{item.roomName} — {item.itemName}</span>
                        {item.description && (
                          <span className="text-gray-600">: {item.description}</span>
                        )}
                        {item.repairQuote && (
                          <span className="text-gray-500"> — Repair quote: {item.repairQuote}</span>
                        )}
                        <MediaThumbnails mediaUrls={(item.mediaUrls as string[]) || []} />
                        <OwnerItemResponse item={item} token={token!} isMissingOrReplacement={false} />
                      </div>
                    </li>
                  ))}
                </ul>
              </div>
            )}
          </Card>
        )}

        {missingItems.length > 0 && (
          <Card className="p-6 bg-white" data-testid="section-missing">
            <h2 className="text-lg font-bold text-gray-900 border-b-2 border-purple-500 pb-2 mb-4">
              Missing Items
            </h2>
            <p className="text-sm text-gray-600 mb-3">
              Here's the list of items identified as missing:
            </p>
            <ul className="space-y-4">
              {missingItems.map((item) => (
                <li key={item.id} className="pl-6 border-l-2 border-purple-200" data-testid={`public-missing-${item.id}`}>
                  <div className="flex-1">
                    <span className="font-medium text-gray-900">{item.roomName} — {item.itemName}</span>
                    {item.description && (
                      <span className="text-gray-600">: {item.description}</span>
                    )}
                    <MediaThumbnails mediaUrls={(item.mediaUrls as string[]) || []} />
                    <OwnerItemResponse item={item} token={token!} isMissingOrReplacement={true} />
                  </div>
                </li>
              ))}
            </ul>
            {report.amazonCartLink && (
              <AmazonCartSection amazonCartLink={report.amazonCartLink} />
            )}
          </Card>
        )}

        {Object.entries(groupedByCategory)
          .filter(([catName]) => catName !== "Damage" && catName !== "Missing" && catName !== "Good")
          .map(([catName, catItems]) => {
            const cat = categories.find((c) => c.name === catName);
            const isMissingOrReplacement = catName === "Replacement";
            return (
              <Card key={catName} className="p-6 bg-white" data-testid={`section-${catName.toLowerCase()}`}>
                <h2
                  className="text-lg font-bold text-gray-900 pb-2 mb-4"
                  style={{ borderBottom: `2px solid ${cat?.color || "#6b7280"}` }}
                >
                  {catName}
                </h2>
                <ul className="space-y-4">
                  {catItems.map((item) => (
                    <li key={item.id} className="pl-6 border-l-2" style={{ borderColor: `${cat?.color || "#6b7280"}40` }}>
                      <div className="flex-1">
                        <span className="font-medium text-gray-900">{item.roomName} — {item.itemName}</span>
                        {item.description && (
                          <span className="text-gray-600">: {item.description}</span>
                        )}
                        <MediaThumbnails mediaUrls={(item.mediaUrls as string[]) || []} />
                        <OwnerItemResponse item={item} token={token!} isMissingOrReplacement={isMissingOrReplacement} />
                      </div>
                    </li>
                  ))}
                </ul>
                {isMissingOrReplacement && report.amazonCartLink && (
                  <AmazonCartSection amazonCartLink={report.amazonCartLink} />
                )}
              </Card>
            );
          })}

        {items.filter((i) => {
          const cat = categoryMap.get(i.categoryId);
          return cat?.name !== "Good";
        }).length === 0 && (
          <Card className="p-8 text-center bg-white">
            <CheckCircle2 className="w-12 h-12 mx-auto text-green-500 mb-4" />
            <h3 className="text-lg font-semibold text-gray-900 mb-2">All Clear</h3>
            <p className="text-gray-500">No issues to report for this inspection.</p>
          </Card>
        )}

        {report.closingMessage && items.filter((i) => {
          const cat = categoryMap.get(i.categoryId);
          return cat?.name !== "Good";
        }).length > 0 && (
          <Card className="p-6 bg-white" data-testid="section-closing">
            <p className="text-sm text-gray-700">{report.closingMessage}</p>
          </Card>
        )}

        <div className="text-center text-xs text-gray-400 py-4">
          <p>Generated by Toronto Boutique Apartments Inspection System</p>
          <p>Report generated on {new Date(report.updatedAt).toLocaleDateString()}</p>
        </div>
      </div>
    </div>
  );
}

